const items = $input.all();

const excludedPondIds = new Set([
  1, 2, 6, 9, 27, 28, 30, 32, 33, 35, 41, 97, 113, 179, 182, 199,
  208, 209, 214, 219, 229, 230, 238, 240, 241, 242, 244, 246, 248,
  253, 255, 257, 260, 263, 264, 265, 266, 267, 268, 269, 270, 272,
  273, 274, 275, 276, 277, 278, 279, 280
]);

const skipStageIds = new Set([8, 20, 21, 27]);
const claudiaUserId = 692;
const createdOlderThanDays = 90;
const recentActivityDays = 30;

const now = new Date();
const MS_PER_DAY = 1000 * 60 * 60 * 24;

const createdCutoff = new Date(
  now.getTime() - createdOlderThanDays * 24 * 60 * 60 * 1000
);

function parseDate(value) {
  if (!value) return null;

  const date = new Date(value);

  return Number.isNaN(date.getTime()) ? null : date;
}

function toIsoOrNull(value) {
  const date = parseDate(value);
  return date ? date.toISOString() : null;
}

function daysSince(value) {
  const date = parseDate(value);
  if (!date) return null;

  const diff = now.getTime() - date.getTime();

  if (diff < 0) return 0;

  return Math.floor(diff / MS_PER_DAY);
}

function isWithinDays(value, days) {
  const diffDays = daysSince(value);
  return diffDays !== null && diffDays <= days;
}

function normalizeContacted(value) {
  if (value === true || value === 1 || value === '1') return true;
  if (value === false || value === 0 || value === '0') return false;
  return Boolean(value);
}

function hasAddress(lead) {
  const addresses = lead.addresses || [];

  if (!Array.isArray(addresses) || addresses.length === 0) {
    return false;
  }

  return addresses.some(address =>
    Boolean(address?.value || address?.address || address?.street)
  );
}

function hasValidPhone(lead) {
  const phones = lead.phones || [];

  if (!Array.isArray(phones) || phones.length === 0) {
    return false;
  }

  return phones.some(phone =>
    String(phone?.status || '').toLowerCase() === 'valid'
  );
}

function getRejectReason(lead) {
  if (!['Zillow', 'Zillow Preferred'].includes(lead.source)) {
    return 'invalid_source';
  }

  if (hasAddress(lead)) {
    return 'has_address';
  }

  if (!hasValidPhone(lead)) {
    return 'no_valid_phone';
  }

  if (Number(lead.assignedUserId) === claudiaUserId) {
    return 'claudia_negrete';
  }

  const pondId =
    lead.assignedPondId === null || lead.assignedPondId === undefined
      ? null
      : Number(lead.assignedPondId);

  if (pondId && excludedPondIds.has(pondId)) {
    return 'excluded_pond';
  }

  const stageId =
    lead.stageId === null || lead.stageId === undefined
      ? null
      : Number(lead.stageId);

  if (stageId && skipStageIds.has(stageId)) {
    return 'closed_or_under_contract';
  }

  const created = parseDate(lead.created);

  if (!created) {
    return 'no_created_date';
  }

  if (created >= createdCutoff) {
    return 'created_under_90_days';
  }

  return null;
}

const rejectionCounts = {};
const passed = [];
const rejected = [];

for (const item of items) {
  const lead = item.json;
  const reason = getRejectReason(lead);

  if (reason) {
    rejectionCounts[reason] = (rejectionCounts[reason] || 0) + 1;

    rejected.push({
      id: lead.id,
      name: lead.name,
      reason
    });

    continue;
  }

  const contactedFlag = normalizeContacted(lead.contacted);
  const lastActivity = lead.lastActivity || lead.last_activity || '';

  passed.push({
    json: {
      item_type: 'phase_1_validated_lead',

      lead_id: lead.id,
      id: lead.id,
      name: lead.name || '',

      source: lead.source || '',
      created: lead.created || '',

      last_activity: lastActivity,
      last_activity_iso: toIsoOrNull(lastActivity),
      days_since_last_activity: daysSince(lastActivity),
      last_activity_within_30d_fyi: isWithinDays(lastActivity, recentActivityDays),

      contacted: lead.contacted ?? 0,
      contacted_flag: contactedFlag,

      agent_id: lead.assignedUserId ?? null,
      agent_name: lead.assignedTo || '',

      pond_id: lead.assignedPondId ?? null,

      stage_id: lead.stageId ?? null,
      stage: lead.stage || '',

      phones: lead.phones || [],
      addresses: lead.addresses || [],
      collaborators: lead.collaborators || [],

      phase_1_status: 'passed'
    }
  });
}

return [
  {
    json: {
      item_type: 'summary',
      phase: 'phase_1_validation',
      created_at: now.toISOString(),
      input_leads: items.length,
      passed_leads: passed.length,
      rejected_leads: rejected.length,
      rejection_counts: rejectionCounts,
      rejected_sample: rejected.slice(0, 20)
    }
  },
  ...passed
];

const items = $input.all();

function toDate(value) {
  if (!value) return null;
  const d = new Date(value);
  return Number.isNaN(d.getTime()) ? null : d;
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function firstValidNumber(values) {
  for (const value of values) {
    const num = Number(value);
    if (Number.isFinite(num) && num > 0) {
      return num;
    }
  }
  return null;
}

function extractPersonIdFromUrl(url) {
  if (!url || typeof url !== 'string') return null;

  const match = url.match(/[?&]personId=(\d+)/);
  if (!match) return null;

  const num = Number(match[1]);
  return Number.isFinite(num) && num > 0 ? num : null;
}

function getResponseBody(json) {
  if (json.body && typeof json.body === 'object') {
    return json.body;
  }

  return json || {};
}

function getMetadata(raw, response) {
  return response._metadata || raw._metadata || {};
}

return items.map((item, index) => {
  const raw = item.json || {};
  const response = getResponseBody(raw);
  const metadata = getMetadata(raw, response);
  const statusCode = raw.statusCode || raw.status || response.statusCode || response.status || null;
  const callsApiError = Boolean((statusCode && Number(statusCode) >= 400) || raw.error || response.error);
  const callsApiErrorMessage = raw.error?.message || response.error?.message || raw.message || response.message || null;

  const rawCalls = asArray(
    response.calls ||
    raw.calls ||
    response.recent_calls ||
    raw.recent_calls
  );

  const normalizedCalls = rawCalls
    .map(call => ({
      id: call.id ?? call.call_id ?? null,
      personId: call.personId ?? call.person_id ?? null,
      created: call.created ?? call.createdAt ?? call.startedAt ?? call.date ?? null,
      startedAt: call.startedAt ?? call.started_at ?? null,
      userId: call.userId ?? call.user_id ?? null,
      userName: call.userName ?? call.user_name ?? null,
      duration: call.duration ?? null,
      outcome: call.outcome ?? null,
      isIncoming: call.isIncoming ?? call.is_incoming ?? null,
      note: call.note ?? null,
      phone: call.phone ?? null,
      fromNumber: call.fromNumber ?? null,
      toNumber: call.toNumber ?? null
    }))
    .filter(call =>
      call.id ||
      call.personId ||
      call.created ||
      call.startedAt
    )
    .sort((a, b) => {
      const da = toDate(a.created || a.startedAt)?.getTime() ?? 0;
      const db = toDate(b.created || b.startedAt)?.getTime() ?? 0;
      return db - da;
    });

  const latestCall = normalizedCalls[0] || null;

  const leadId = firstValidNumber([
    raw.lead_id,
    raw.id,
    raw.personId,
    raw.person_id,

    response.lead_id,
    response.id,
    response.personId,
    response.person_id,

    raw.query?.personId,
    raw.params?.personId,
    raw.request?.query?.personId,
    raw.request?.qs?.personId,

    response.query?.personId,
    response.params?.personId,
    response.request?.query?.personId,
    response.request?.qs?.personId,

    latestCall?.personId,

    extractPersonIdFromUrl(metadata.nextLink),
    extractPersonIdFromUrl(raw.request_url),
    extractPersonIdFromUrl(raw.url),
    extractPersonIdFromUrl(response.request_url),
    extractPersonIdFromUrl(response.url),
  ]);

  const latestCallPersonId =
    latestCall?.personId !== undefined && latestCall?.personId !== null
      ? Number(latestCall.personId)
      : null;

  const reportedTotalRaw = metadata.total;
  const reportedTotalNumber = Number(reportedTotalRaw);

  const callsTotalReportedByFub =
    Number.isFinite(reportedTotalNumber)
      ? Math.max(reportedTotalNumber, normalizedCalls.length)
      : normalizedCalls.length;

  const warnings = [];

  if (!leadId) {
    warnings.push('lead_id_not_found');
  }

  if (
    latestCallPersonId &&
    leadId &&
    latestCallPersonId !== leadId
  ) {
    warnings.push(`latest_call_person_id_mismatch:${latestCallPersonId}`);
  }

  if (
    Number.isFinite(reportedTotalNumber) &&
    reportedTotalNumber < normalizedCalls.length
  ) {
    warnings.push('metadata_total_lower_than_returned_calls');
  }

  const callsProfileType =
    !leadId
      ? 'lead_id_missing'
      : normalizedCalls.length > 0
        ? 'with_calls'
        : 'empty_no_calls';

  return {
    json: {
      lead_id: leadId,

      calls_profile_built: true,
      calls_api_error: callsApiError,
      calls_api_error_message: callsApiErrorMessage,
      calls_http_status_code: statusCode,
      calls_profile_type: callsProfileType,

      calls_total_reported_by_fub: callsTotalReportedByFub,
      calls_total_returned: normalizedCalls.length,

      latest_call_found: Boolean(latestCall),
      latest_call_id: latestCall?.id ?? null,
      latest_call_person_id: latestCallPersonId,
      latest_call_date: latestCall?.created ?? null,
      latest_call_started_at: latestCall?.startedAt ?? null,
      latest_call_user_id: latestCall?.userId ?? null,
      latest_call_user_name: latestCall?.userName ?? null,
      latest_call_duration: latestCall?.duration ?? null,
      latest_call_outcome: latestCall?.outcome ?? null,
      latest_call_is_incoming: latestCall?.isIncoming ?? null,
      latest_call_note: latestCall?.note ?? null,

      recent_calls: normalizedCalls.map(call => ({
        id: call.id,
        personId: call.personId,
        created: call.created,
        startedAt: call.startedAt,
        userId: call.userId,
        userName: call.userName,
        duration: call.duration,
        outcome: call.outcome,
        isIncoming: call.isIncoming
      })),

      calls_profile_warning: warnings.length ? warnings.join('|') : null,
      build_calls_profile_index: index
    }
  };
});

const items = $input.all();

function toDate(value) {
  if (!value) return null;
  const d = new Date(value);
  return Number.isNaN(d.getTime()) ? null : d;
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function firstValidNumber(values) {
  for (const value of values) {
    const num = Number(value);
    if (Number.isFinite(num) && num > 0) {
      return num;
    }
  }
  return null;
}

function extractPersonIdFromUrl(url) {
  if (!url || typeof url !== 'string') return null;

  const match = url.match(/[?&]personId=(\d+)/);
  if (!match) return null;

  const num = Number(match[1]);
  return Number.isFinite(num) && num > 0 ? num : null;
}

function getResponseBody(json) {
  if (json.body && typeof json.body === 'object') {
    return json.body;
  }

  if (json.texts_response && typeof json.texts_response === 'object') {
    return json.texts_response;
  }

  return json || {};
}

function getMetadata(raw, response) {
  return response._metadata || raw._metadata || {};
}

function addScore(map, value, score = 1) {
  const num = Number(value);
  if (!Number.isFinite(num) || num <= 0) return;

  map.set(num, (map.get(num) || 0) + score);
}

function getBestScoredPersonId(scoreMap) {
  const entries = [...scoreMap.entries()].sort((a, b) => b[1] - a[1]);
  return entries.length ? entries[0][0] : null;
}

function normalizeParticipants(participants) {
  if (!Array.isArray(participants)) return [];

  return participants.map(participant => ({
    name: participant.name ?? null,
    type: participant.type ?? null,
    phone: participant.phone ?? null,
    phoneLabel: participant.phoneLabel ?? null,
    sender: participant.sender ?? null,
    canReply: participant.canReply ?? null,
    personId: participant.personId ?? null,
    userId: participant.userId ?? null,
    relationshipId: participant.relationshipId ?? null,
    summaryAccessOnly: participant.summaryAccessOnly ?? null
  }));
}

function getCandidateScoresFromTexts(texts) {
  const scores = new Map();

  for (const text of texts) {
    const isGroupText = Boolean(text.groupTextId);

    if (!isGroupText) {
      addScore(scores, text.personId, 5);
    } else {
      addScore(scores, text.personId, 1);
    }

    for (const participant of asArray(text.participants)) {
      if (participant?.type === 'person') {
        addScore(scores, participant.personId, 4);
      }
    }
  }

  return scores;
}

return items.map((item, index) => {
  const raw = item.json || {};
  const response = getResponseBody(raw);
  const metadata = getMetadata(raw, response);
  const statusCode = raw.statusCode || raw.status || response.statusCode || response.status || null;
  const textsApiError = Boolean((statusCode && Number(statusCode) >= 400) || raw.error || response.error);
  const textsApiErrorMessage = raw.error?.message || response.error?.message || raw.message || response.message || null;

  const textsRaw =
    asArray(response.textmessages).length ? asArray(response.textmessages) :
    asArray(response.textMessages).length ? asArray(response.textMessages) :
    asArray(response.texts).length ? asArray(response.texts) :
    asArray(raw.textmessages).length ? asArray(raw.textmessages) :
    asArray(raw.textMessages).length ? asArray(raw.textMessages) :
    asArray(raw.texts);

  const normalizedTexts = textsRaw
    .map(text => {
      const participants = normalizeParticipants(text.participants);

      return {
        id: text.id ?? text.text_id ?? null,
        personId: text.personId ?? text.person_id ?? null,

        created: text.created ?? text.createdAt ?? text.dateCreated ?? text.sent ?? text.sentAt ?? null,
        sent: text.sent ?? text.sentAt ?? null,
        updated: text.updated ?? text.updatedAt ?? null,

        createdById: text.createdById ?? text.created_by_id ?? null,
        updatedById: text.updatedById ?? text.updated_by_id ?? null,

        userId: text.userId ?? text.user_id ?? text.createdById ?? text.created_by_id ?? null,
        userName: text.userName ?? text.user_name ?? null,

        name: text.name ?? null,
        firstName: text.firstName ?? null,
        lastName: text.lastName ?? null,

        status: text.status ?? null,
        message: text.message ?? text.body ?? null,

        fromNumber: text.fromNumber ?? text.from_number ?? null,
        toNumber: text.toNumber ?? text.to_number ?? null,

        isIncoming: text.isIncoming ?? text.is_incoming ?? null,
        archived: text.archived ?? null,
        read: text.read ?? null,

        sharedInboxId: text.sharedInboxId ?? null,
        actionPlanId: text.actionPlanId ?? null,
        leadFlowRouteId: text.leadFlowRouteId ?? null,

        groupTextId: text.groupTextId ?? text.group_text_id ?? null,
        isGroupText: Boolean(text.groupTextId ?? text.group_text_id),

        isExternal: text.isExternal ?? null,
        externalUrl: text.externalUrl ?? null,
        externalLabel: text.externalLabel ?? null,

        systemId: text.systemId ?? null,
        systemName: text.systemName ?? null,

        deliveryStatus: text.deliveryStatus ?? text.delivery_status ?? null,
        deliveryStatusDate: text.deliveryStatusDate ?? text.delivery_status_date ?? null,
        deliveryStatusError: text.deliveryStatusError ?? text.delivery_status_error ?? null,
        deliveryStatusErrorCode: text.deliveryStatusErrorCode ?? text.delivery_status_error_code ?? null,

        mediaCount: Array.isArray(text.media) ? text.media.length : 0,
        participants
      };
    })
    .filter(text =>
      text.id ||
      text.personId ||
      text.created ||
      text.sent ||
      text.updated
    )
    .sort((a, b) => {
      const da = toDate(a.created || a.sent || a.updated)?.getTime() ?? 0;
      const db = toDate(b.created || b.sent || b.updated)?.getTime() ?? 0;
      return db - da;
    });

  const latestText = normalizedTexts[0] || null;

  const preservedLeadId = firstValidNumber([
    raw.lead_id,
    raw.requested_person_id,
    raw.requestedPersonId,
    raw.person_id,
    raw.personId,
    raw.id,

    response.lead_id,
    response.requested_person_id,
    response.requestedPersonId,
    response.person_id,
    response.personId,
    response.id,

    raw.query?.personId,
    raw.params?.personId,
    raw.request?.query?.personId,
    raw.request?.qs?.personId,

    response.query?.personId,
    response.params?.personId,
    response.request?.query?.personId,
    response.request?.qs?.personId,
  ]);

  const metadataLeadId = firstValidNumber([
    extractPersonIdFromUrl(metadata.nextLink),
    extractPersonIdFromUrl(metadata.previousLink),
    extractPersonIdFromUrl(metadata.selfLink),
    extractPersonIdFromUrl(metadata.url),
    extractPersonIdFromUrl(raw.request_url),
    extractPersonIdFromUrl(raw.url),
    extractPersonIdFromUrl(response.request_url),
    extractPersonIdFromUrl(response.url),
  ]);

  const candidateScores = getCandidateScoresFromTexts(normalizedTexts);
  const inferredLeadId = getBestScoredPersonId(candidateScores);

  const leadId = firstValidNumber([
    preservedLeadId,
    metadataLeadId,
    inferredLeadId
  ]);

  const latestTextPersonId =
    latestText?.personId !== undefined && latestText?.personId !== null
      ? Number(latestText.personId)
      : null;

  const latestTextParticipantsPersonIds = [
    ...new Set(
      asArray(latestText?.participants)
        .filter(p => p.type === 'person')
        .map(p => Number(p.personId))
        .filter(num => Number.isFinite(num) && num > 0)
    )
  ];

  const leadIsInLatestTextParticipants =
    Boolean(leadId) &&
    latestTextParticipantsPersonIds.includes(Number(leadId));

  const warnings = [];

  if (!leadId) {
    warnings.push('lead_id_not_found');
  }

  if (
    latestTextPersonId &&
    leadId &&
    latestTextPersonId !== Number(leadId) &&
    !leadIsInLatestTextParticipants
  ) {
    warnings.push(`latest_text_person_id_mismatch:${latestTextPersonId}`);
  }

  const reportedTotalRaw = metadata.total;
  const reportedTotalNumber = Number(reportedTotalRaw);

  const textsTotalReportedByFub =
    Number.isFinite(reportedTotalNumber)
      ? Math.max(reportedTotalNumber, normalizedTexts.length)
      : normalizedTexts.length;

  if (
    Number.isFinite(reportedTotalNumber) &&
    reportedTotalNumber < normalizedTexts.length
  ) {
    warnings.push('metadata_total_lower_than_returned_texts');
  }

  const leadIdInferenceSource =
    preservedLeadId ? 'preserved_input' :
    metadataLeadId ? 'metadata_link' :
    inferredLeadId ? 'inferred_from_texts_and_participants' :
    null;

  const textsProfileType =
    !leadId
      ? 'lead_id_missing'
      : normalizedTexts.length > 0
        ? 'with_texts'
        : 'empty_no_texts';

  return {
    json: {
      lead_id: leadId,

      texts_profile_built: true,
      texts_api_error: textsApiError,
      texts_api_error_message: textsApiErrorMessage,
      texts_http_status_code: statusCode,
      texts_profile_type: textsProfileType,
      lead_id_inference_source: leadIdInferenceSource,

      texts_total_reported_by_fub: textsTotalReportedByFub,
      texts_total_returned: normalizedTexts.length,

      latest_text_found: Boolean(latestText),
      latest_text_id: latestText?.id ?? null,
      latest_text_person_id: latestTextPersonId,

      latest_text_date: latestText?.created ?? latestText?.sent ?? latestText?.updated ?? null,
      latest_text_sent_at: latestText?.sent ?? null,
      latest_text_updated_at: latestText?.updated ?? null,

      latest_text_user_id: latestText?.userId ?? null,
      latest_text_user_name: latestText?.userName ?? null,
      latest_text_created_by_id: latestText?.createdById ?? null,

      latest_text_status: latestText?.status ?? null,
      latest_text_is_incoming: latestText?.isIncoming ?? null,
      latest_text_archived: latestText?.archived ?? null,
      latest_text_read: latestText?.read ?? null,

      latest_text_from_number: latestText?.fromNumber ?? null,
      latest_text_to_number: latestText?.toNumber ?? null,

      latest_text_delivery_status: latestText?.deliveryStatus ?? null,
      latest_text_delivery_status_date: latestText?.deliveryStatusDate ?? null,
      latest_text_delivery_status_error: latestText?.deliveryStatusError ?? null,
      latest_text_delivery_status_error_code: latestText?.deliveryStatusErrorCode ?? null,

      latest_text_group_text_id: latestText?.groupTextId ?? null,
      latest_text_is_group_text: latestText?.isGroupText ?? false,
      latest_text_participants_count: latestText?.participants?.length ?? 0,
      latest_text_participants_person_ids: latestTextParticipantsPersonIds,
      lead_is_in_latest_text_participants: leadIsInLatestTextParticipants,

      latest_text_media_count: latestText?.mediaCount ?? 0,

      recent_texts: normalizedTexts.map(text => ({
        id: text.id,
        personId: text.personId,
        created: text.created,
        sent: text.sent,
        updated: text.updated,
        userId: text.userId,
        userName: text.userName,
        status: text.status,
        isIncoming: text.isIncoming,
        fromNumber: text.fromNumber,
        toNumber: text.toNumber,
        deliveryStatus: text.deliveryStatus,
        groupTextId: text.groupTextId,
        isGroupText: text.isGroupText,
        participants: text.participants
      })),

      text_person_id_candidates: [...candidateScores.entries()]
        .map(([personId, score]) => ({ personId, score }))
        .sort((a, b) => b.score - a.score),

      texts_profile_warning: warnings.length ? warnings.join('|') : null,
      build_text_profile_index: index
    }
  };
});

const items = $input.all();

/**
 * Ajusta esta zona horaria si tu operaciÃ³n debe evaluarse con otra fecha local.
 * Para Zillow / California, America/Los_Angeles suele ser lo mÃ¡s seguro.
 */
const TIME_ZONE = 'America/Los_Angeles';

function firstValidNumber(values) {
  for (const value of values) {
    const num = Number(value);
    if (Number.isFinite(num) && num > 0) {
      return num;
    }
  }
  return null;
}

function extractPersonIdFromUrl(url) {
  if (!url || typeof url !== 'string') return null;

  const match = url.match(/[?&]personId=(\d+)/);
  if (!match) return null;

  const num = Number(match[1]);
  return Number.isFinite(num) && num > 0 ? num : null;
}

function isDateOnly(value) {
  return typeof value === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(value);
}

function toDate(value) {
  if (!value) return null;

  const d = new Date(value);
  return Number.isNaN(d.getTime()) ? null : d;
}

function getTodayYmd(timeZone) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(new Date());

  const map = {};
  for (const part of parts) {
    if (part.type !== 'literal') {
      map[part.type] = part.value;
    }
  }

  return `${map.year}-${map.month}-${map.day}`;
}

function normalizeCompleted(task) {
  /**
   * En el output real de FUB viene:
   * isCompleted: 1 / 0
   * completed: timestamp / null
   */
  const value =
    task.isCompleted ??
    task.completed ??
    task.status ??
    null;

  if (value === true) return true;
  if (value === false) return false;

  if (value === 1 || value === '1') return true;
  if (value === 0 || value === '0') return false;

  if (typeof value === 'string') {
    const clean = value.trim().toLowerCase();

    if (
      clean &&
      !['false', '0', 'open', 'pending', 'todo', 'active'].includes(clean)
    ) {
      /**
       * Si completed trae una fecha tipo "2026-05-15T18:27:16Z",
       * la tarea estÃ¡ completada.
       */
      const maybeDate = new Date(value);
      if (!Number.isNaN(maybeDate.getTime())) {
        return true;
      }
    }

    if (['true', 'completed', 'complete', 'done', 'closed'].includes(clean)) {
      return true;
    }

    if (['false', 'open', 'pending', 'todo', 'active'].includes(clean)) {
      return false;
    }
  }

  return false;
}

function getDueInfo(task, isCompleted) {
  const dueDateRaw =
    task.dueDate ??
    task.due ??
    task.dueAt ??
    task.dateDue ??
    null;

  const dueDateTimeRaw =
    task.dueDateTime ??
    task.dueTime ??
    null;

  if (isCompleted) {
    return {
      dueDate: dueDateRaw,
      dueDateTime: dueDateTimeRaw,
      dueStatus: 'completed',
      dueDateIsValid: Boolean(dueDateRaw || dueDateTimeRaw),
      isOverdue: false,
      isDueToday: false,
      isFuture: false,
      isActiveNonOverdue: false,
    };
  }

  /**
   * Si FUB trae dueDateTime, es mÃ¡s preciso que dueDate.
   */
  if (dueDateTimeRaw) {
    const dueDateTime = toDate(dueDateTimeRaw);

    if (!dueDateTime) {
      return {
        dueDate: dueDateRaw,
        dueDateTime: dueDateTimeRaw,
        dueStatus: 'invalid_due_datetime',
        dueDateIsValid: false,
        isOverdue: false,
        isDueToday: false,
        isFuture: false,
        isActiveNonOverdue: true,
      };
    }

    const now = new Date();

    if (dueDateTime.getTime() < now.getTime()) {
      return {
        dueDate: dueDateRaw,
        dueDateTime: dueDateTimeRaw,
        dueStatus: 'overdue',
        dueDateIsValid: true,
        isOverdue: true,
        isDueToday: false,
        isFuture: false,
        isActiveNonOverdue: false,
      };
    }

    return {
      dueDate: dueDateRaw,
      dueDateTime: dueDateTimeRaw,
      dueStatus: 'future',
      dueDateIsValid: true,
      isOverdue: false,
      isDueToday: false,
      isFuture: true,
      isActiveNonOverdue: true,
    };
  }

  /**
   * Si solo viene YYYY-MM-DD, se evalÃºa como fecha calendario.
   * AsÃ­ evitamos que una tarea de hoy quede vencida a las 00:00.
   */
  if (dueDateRaw && isDateOnly(dueDateRaw)) {
    const todayYmd = getTodayYmd(TIME_ZONE);

    if (dueDateRaw < todayYmd) {
      return {
        dueDate: dueDateRaw,
        dueDateTime: dueDateTimeRaw,
        dueStatus: 'overdue',
        dueDateIsValid: true,
        isOverdue: true,
        isDueToday: false,
        isFuture: false,
        isActiveNonOverdue: false,
      };
    }

    if (dueDateRaw === todayYmd) {
      return {
        dueDate: dueDateRaw,
        dueDateTime: dueDateTimeRaw,
        dueStatus: 'due_today',
        dueDateIsValid: true,
        isOverdue: false,
        isDueToday: true,
        isFuture: false,
        isActiveNonOverdue: true,
      };
    }

    return {
      dueDate: dueDateRaw,
      dueDateTime: dueDateTimeRaw,
      dueStatus: 'future',
      dueDateIsValid: true,
      isOverdue: false,
      isDueToday: false,
      isFuture: true,
      isActiveNonOverdue: true,
    };
  }

  if (dueDateRaw) {
    const dueDate = toDate(dueDateRaw);

    if (!dueDate) {
      return {
        dueDate: dueDateRaw,
        dueDateTime: dueDateTimeRaw,
        dueStatus: 'invalid_due_date',
        dueDateIsValid: false,
        isOverdue: false,
        isDueToday: false,
        isFuture: false,
        isActiveNonOverdue: true,
      };
    }

    if (dueDate.getTime() < Date.now()) {
      return {
        dueDate: dueDateRaw,
        dueDateTime: dueDateTimeRaw,
        dueStatus: 'overdue',
        dueDateIsValid: true,
        isOverdue: true,
        isDueToday: false,
        isFuture: false,
        isActiveNonOverdue: false,
      };
    }

    return {
      dueDate: dueDateRaw,
      dueDateTime: dueDateTimeRaw,
      dueStatus: 'future',
      dueDateIsValid: true,
      isOverdue: false,
      isDueToday: false,
      isFuture: true,
      isActiveNonOverdue: true,
    };
  }

  return {
    dueDate: null,
    dueDateTime: null,
    dueStatus: 'no_due_date',
    dueDateIsValid: false,
    isOverdue: false,
    isDueToday: false,
    isFuture: false,
    isActiveNonOverdue: true,
  };
}

function sortByDueAsc(a, b) {
  const aValue = a.dueDateTime || a.dueDate || '9999-12-31T23:59:59Z';
  const bValue = b.dueDateTime || b.dueDate || '9999-12-31T23:59:59Z';

  return String(aValue).localeCompare(String(bValue));
}

return items.map(item => {
