      has_future_task: futureTasks.length > 0,
      has_no_due_date_task: noDueDateTasks.length > 0,
      has_active_nonoverdue_task: activeNonOverdueTasks.length > 0,

      oldest_overdue_task_id: oldestOverdueTask?.id ?? null,
