/****************************************************************************************
 * NODE: Build Full Lead Profile
 * MODE: Run Once for All Items
 *
 * OBJETIVO:
 * - Recibir items mezclados de:
 *   1) Lead base / Phase 1
 *   2) Calls + Texts
 *   3) Last Communication Review
 *   4) Tasks Profile
 *   5) Notes Profile
 *
 * - Unir todo por lead_id.
 * - Crear un perfil único por lead.
 * - Mantener la información separada por bloques:
 *   lead_info
 *   communication_profile
 *   tasks_profile
 *   notes_profile
 *   action_eligibility
 *
 * - Clasificar la acción recomendada:
 *   NO_ACTION
 *   S1_REASSIGN_POND
 *   S2_WARNING_NOTE
 *
 * REGLA SEGURA:
 * - Si falta communication profile, tasks profile o notes profile:
 *   => NO_ACTION
 * - Si Notes API falla:
 *   => NO_ACTION
 *
 * NUEVA REGLA WARNING:
 * - Sin comunicación 30+ días + sin tareas abiertas:
 *   => S1_REASSIGN_POND
 * - Sin comunicación 30+ días + tarea activa/no vencida:
 *   => NO_ACTION
 * - Sin comunicación 30+ días + tarea vencida + sin warning previo:
 *   => S2_WARNING_NOTE
 * - Sin comunicación 30+ días + tarea vencida + warning previo menor a 7 días:
 *   => NO_ACTION
 * - Sin comunicación 30+ días + tarea vencida + warning previo de 7+ días:
 *   => S1_REASSIGN_POND
 ****************************************************************************************/

const items = $input.all();

const COMMUNICATION_THRESHOLD_DAYS = 30;
const WARNING_ESCALATION_DAYS = 7;
const MS_PER_DAY = 1000 * 60 * 60 * 24;

const INCLUDE_SUMMARY = false;

// Para pruebas puedes fijar fecha:
// const NOW_OVERRIDE = '2026-06-10T00:00:00Z';
const NOW_OVERRIDE = null;

const now = NOW_OVERRIDE ? new Date(NOW_OVERRIDE) : new Date();

function normalizeInput(items) {
  if (items.length > 1) {
    return items.map(item => item.json);
  }

  const first = items[0]?.json;

  if (Array.isArray(first)) return first;
  if (Array.isArray(first?.data)) return first.data;
  if (Array.isArray(first?.results)) return first.results;
  if (Array.isArray(first?.leads)) return first.leads;

  return first ? [first] : [];
}

function toNumberOrNull(value) {
  const num = Number(value);
  return Number.isFinite(num) ? num : null;
}

function parseDate(value) {
  if (!value) return null;

  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
}

function daysSinceDate(date) {
  if (!date) return null;

  const diffMs = now.getTime() - date.getTime();

  if (diffMs < 0) return 0;

  return Math.floor(diffMs / MS_PER_DAY);
}

function bool(value) {
  return value === true || value === 1 || value === '1';
}

function getLeadId(record) {
  return (
    toNumberOrNull(record.lead_id) ??
    toNumberOrNull(record.id) ??
    toNumberOrNull(record.personId) ??
    toNumberOrNull(record.person_id) ??
    toNumberOrNull(record.latest_call_person_id) ??
    toNumberOrNull(record.latest_text_person_id) ??
    toNumberOrNull(record.latest_warning_note_person_id) ??
    null
  );
}

function hasAnyKey(record, keys) {
  return keys.some(key => Object.prototype.hasOwnProperty.call(record, key));
}

function isLeadBaseRecord(record) {
  return (
    record.item_type === 'phase_1_validated_lead' ||
