function getLatestCommunicationFallback(record) {
  const candidates = [];

  const callDate = parseDate(
    record?.latest_call_date ||
    record?.latest_call_started_at ||
    null
  );

  if (callDate) {
    candidates.push({
      source: 'call',
      date: callDate,
      raw: record.latest_call_date || record.latest_call_started_at,
    });
  }

  const textDate = parseDate(
    record?.latest_text_date ||
    record?.latest_text_sent_at ||
    record?.latest_text_updated_at ||
    null
  );

  if (textDate) {
    candidates.push({
      source: 'text',
      date: textDate,
      raw:
        record.latest_text_date ||
        record.latest_text_sent_at ||
        record.latest_text_updated_at,
    });
  }

  if (candidates.length === 0) return null;

  candidates.sort((a, b) => b.date.getTime() - a.date.getTime());

  return candidates[0];
}

function deriveCommunicationStatus(communicationProfile) {
  if (!communicationProfile) {
    return {
      latest_communication_found: false,
      latest_communication_date: null,
      latest_communication_source: null,
      days_since_latest_communication: null,
      no_communication_found: null,
      last_communication_gt_30d: null,
      communication_status: 'MISSING_COMMUNICATION_PROFILE',
      action_candidate_by_communication: false,
    };
  }

  const existingReview = communicationProfile.communication_review || {};

  const latestCommunicationDateRaw =
    communicationProfile.latest_communication_date ??
    existingReview.latest_communication_date ??
    null;

  const latestCommunicationDate = parseDate(latestCommunicationDateRaw);

  let fallback = null;

  if (!latestCommunicationDate) {
    fallback = getLatestCommunicationFallback(communicationProfile);
  }

  const finalDate = latestCommunicationDate || fallback?.date || null;

  const latestCommunicationFound =
    bool(communicationProfile.latest_communication_found) ||
    bool(existingReview.latest_communication_found) ||
    Boolean(finalDate);

  const noCommunicationFound =
    communicationProfile.no_communication_found === true ||
    existingReview.no_communication_found === true ||
    !latestCommunicationFound;

  const daysSinceLatestCommunication =
    communicationProfile.days_since_latest_communication ??
    existingReview.days_since_latest_communication ??
    daysSinceDate(finalDate);

  const calculatedGt30 =
    noCommunicationFound ||
    (
      daysSinceLatestCommunication !== null &&
      daysSinceLatestCommunication > COMMUNICATION_THRESHOLD_DAYS
    );

  const lastCommunicationGt30d =
    communicationProfile.last_communication_gt_30d ??
    existingReview.last_communication_gt_30d ??
    calculatedGt30;

  let communicationStatus =
    communicationProfile.communication_status ??
    existingReview.communication_status ??
    null;

  if (!communicationStatus) {
    if (noCommunicationFound) {
      communicationStatus = 'NO_COMMUNICATION_FOUND_FLAGGED';
    } else if (lastCommunicationGt30d) {
      communicationStatus = 'STALE_GT_30_DAYS';
    } else {
      communicationStatus = 'RECENT_WITHIN_30_DAYS';
    }
  }

  const actionCandidateByCommunication =
    communicationProfile.action_candidate_by_communication ??
    existingReview.action_candidate_by_communication ??
    lastCommunicationGt30d;

  return {
    latest_communication_found: latestCommunicationFound,
    latest_communication_date: finalDate ? finalDate.toISOString() : null,
    latest_communication_source:
      communicationProfile.latest_communication_source ??
      existingReview.latest_communication_source ??
      fallback?.source ??
      null,
    days_since_latest_communication: daysSinceLatestCommunication,
    no_communication_found: noCommunicationFound,
    last_communication_gt_30d: Boolean(lastCommunicationGt30d),
    communication_status: communicationStatus,
    action_candidate_by_communication: Boolean(actionCandidateByCommunication),
  };
}

function deriveTasksStatus(tasksProfile) {
  if (!tasksProfile) {
    return {
      tasks_profile_found: false,
      tasks_api_error: null,
      open_tasks_count: null,
      overdue_tasks_count: null,
      active_nonoverdue_tasks_count: null,
      due_today_tasks_count: null,
      future_tasks_count: null,
      no_due_date_tasks_count: null,
      has_zero_tasks: null,
      has_open_tasks: null,
      has_overdue_task: null,
      has_active_nonoverdue_task: null,
      has_due_today_task: null,
      has_future_task: null,
      has_no_due_date_task: null,
      tasks_status: 'MISSING_TASKS_PROFILE',
    };
  }

  const openTasksCount =
    tasksProfile.open_tasks_count !== undefined && tasksProfile.open_tasks_count !== null
      ? Number(tasksProfile.open_tasks_count)
      : Array.isArray(tasksProfile.open_tasks)
        ? tasksProfile.open_tasks.length
        : null;

  const hasOpenTasks =
    tasksProfile.has_open_tasks !== undefined
      ? Boolean(tasksProfile.has_open_tasks)
      : openTasksCount !== null
        ? openTasksCount > 0
        : false;

  const hasZeroTasks =
    tasksProfile.has_zero_tasks !== undefined
      ? Boolean(tasksProfile.has_zero_tasks)
      : openTasksCount !== null
        ? openTasksCount === 0
        : false;

  const hasOverdueTask = Boolean(tasksProfile.has_overdue_task);

  const hasDueTodayTask = Boolean(tasksProfile.has_due_today_task);
  const hasFutureTask = Boolean(tasksProfile.has_future_task);
  const hasNoDueDateTask = Boolean(tasksProfile.has_no_due_date_task);
  const hasActiveNonOverdueTask = Boolean(
    tasksProfile.has_active_nonoverdue_task ||
    hasDueTodayTask ||
    hasFutureTask ||
    hasNoDueDateTask ||
    Number(tasksProfile.active_nonoverdue_tasks_count || 0) > 0
  );

  let tasksStatus = 'UNKNOWN_TASK_STATE';

  if (tasksProfile.tasks_api_error) {
    tasksStatus = 'TASKS_API_ERROR';
  } else if (hasZeroTasks) {
    tasksStatus = 'ZERO_OPEN_TASKS';
  } else if (hasActiveNonOverdueTask) {
    tasksStatus = 'HAS_ACTIVE_NON_OVERDUE_TASK';
  } else if (hasOverdueTask) {
    tasksStatus = 'HAS_OVERDUE_TASK';
  } else if (hasOpenTasks) {
    tasksStatus = 'HAS_OPEN_TASKS_UNCLASSIFIED';
  }

  return {
    tasks_profile_found: true,
    tasks_api_error: Boolean(tasksProfile.tasks_api_error),

    open_tasks_count: openTasksCount,

    overdue_tasks_count: Number(tasksProfile.overdue_tasks_count ?? 0),
    active_nonoverdue_tasks_count: Number(tasksProfile.active_nonoverdue_tasks_count ?? 0),
    due_today_tasks_count: Number(tasksProfile.due_today_tasks_count ?? 0),
    future_tasks_count: Number(tasksProfile.future_tasks_count ?? 0),
    no_due_date_tasks_count: Number(tasksProfile.no_due_date_tasks_count ?? 0),

    has_zero_tasks: hasZeroTasks,
    has_open_tasks: hasOpenTasks,
    has_overdue_task: hasOverdueTask,
    has_active_nonoverdue_task: hasActiveNonOverdueTask,
    has_due_today_task: hasDueTodayTask,
    has_future_task: hasFutureTask,
    has_no_due_date_task: hasNoDueDateTask,

    tasks_status: tasksStatus,
  };
}

function deriveNotesStatus(notesProfile) {
  if (!notesProfile) {
    return {
      notes_profile_found: false,
      notes_api_error: null,
      warning_note_already_exists: null,
      existing_warning_notes_count: null,
      has_warning_note_older_or_equal_7_days: null,
      latest_warning_note_age_days: null,
      oldest_warning_note_age_days: null,
      notes_status: 'MISSING_NOTES_PROFILE',
    };
  }

  const existingWarningNotesCount = Number(notesProfile.existing_warning_notes_count ?? 0);

  const warningNoteAlreadyExists = Boolean(
    notesProfile.warning_note_already_exists === true ||
    existingWarningNotesCount > 0
  );

  const latestWarningNoteAgeDays =
    notesProfile.latest_warning_note_age_days !== undefined &&
    notesProfile.latest_warning_note_age_days !== null
      ? Number(notesProfile.latest_warning_note_age_days)
      : null;

  const oldestWarningNoteAgeDays =
    notesProfile.oldest_warning_note_age_days !== undefined &&
    notesProfile.oldest_warning_note_age_days !== null
      ? Number(notesProfile.oldest_warning_note_age_days)
      : null;

  const calculatedOlderOrEqual7 =
    (oldestWarningNoteAgeDays !== null && oldestWarningNoteAgeDays >= WARNING_ESCALATION_DAYS) ||
    (latestWarningNoteAgeDays !== null && latestWarningNoteAgeDays >= WARNING_ESCALATION_DAYS);

  const hasWarningOlderOrEqual7Days = Boolean(
    notesProfile.has_warning_note_older_or_equal_7_days === true ||
    calculatedOlderOrEqual7
  );

  let notesStatus = 'NO_WARNING_NOTES_FOUND';

  if (notesProfile.notes_api_error) {
    notesStatus = 'NOTES_API_ERROR';
  } else if (warningNoteAlreadyExists && hasWarningOlderOrEqual7Days) {
    notesStatus = 'WARNING_NOTE_OLDER_OR_EQUAL_7_DAYS';
  } else if (warningNoteAlreadyExists) {
    notesStatus = 'WARNING_NOTE_EXISTS_LESS_THAN_7_DAYS';
  }

  return {
    notes_profile_found: true,
    notes_api_error: Boolean(notesProfile.notes_api_error),
    notes_http_status_code: notesProfile.notes_http_status_code ?? null,
    notes_total_returned: Number(notesProfile.notes_total_returned ?? 0),
    notes_total_reported_by_fub: Number(notesProfile.notes_total_reported_by_fub ?? notesProfile.notes_total_returned ?? 0),

    warning_note_already_exists: warningNoteAlreadyExists,
    existing_warning_notes_count: existingWarningNotesCount,
    has_warning_note_older_or_equal_7_days: hasWarningOlderOrEqual7Days,
    warning_note_escalation_threshold_days:
      Number(notesProfile.warning_note_escalation_threshold_days ?? WARNING_ESCALATION_DAYS),

    latest_warning_note_id: notesProfile.latest_warning_note_id ?? null,
    latest_warning_note_created: notesProfile.latest_warning_note_created ?? null,
    latest_warning_note_age_days: latestWarningNoteAgeDays,

    oldest_warning_note_id: notesProfile.oldest_warning_note_id ?? null,
    oldest_warning_note_created: notesProfile.oldest_warning_note_created ?? null,
    oldest_warning_note_age_days: oldestWarningNoteAgeDays,

    notes_status: notesStatus,
  };
}

function deriveRecommendedAction(communicationStatus, tasksStatus, notesStatus) {
  const missingCommunicationProfile =
    !communicationStatus ||
    communicationStatus.communication_status === 'MISSING_COMMUNICATION_PROFILE';

  const missingTasksProfile =
    !tasksStatus ||
    tasksStatus.tasks_status === 'MISSING_TASKS_PROFILE';

  const missingNotesProfile =
    !notesStatus ||
    notesStatus.notes_status === 'MISSING_NOTES_PROFILE';

  if (missingCommunicationProfile || missingTasksProfile || missingNotesProfile) {
    return {
      recommended_action: 'NO_ACTION',
      action_bucket: 'NO_ACTION',
      action_reason: 'Incomplete profile: missing communication profile, tasks profile, or notes profile.',
      should_reassign: false,
      should_create_warning_note: false,
      should_skip: true,
    };
  }

  if (tasksStatus.tasks_api_error) {
    return {
      recommended_action: 'NO_ACTION',
      action_bucket: 'NO_ACTION',
      action_reason: 'Tasks API error. No mutation applied.',
      should_reassign: false,
      should_create_warning_note: false,
      should_skip: true,
    };
  }

  if (notesStatus.notes_api_error) {
    return {
      recommended_action: 'NO_ACTION',
      action_bucket: 'NO_ACTION',
      action_reason: 'Notes API error. No mutation applied.',
      should_reassign: false,
      should_create_warning_note: false,
      should_skip: true,
    };
  }

  const communicationGt30 = communicationStatus.last_communication_gt_30d === true;

  if (!communicationGt30) {
    return {
      recommended_action: 'NO_ACTION',
      action_bucket: 'NO_ACTION',
      action_reason: 'Communication found within 30 days.',
      should_reassign: false,
      should_create_warning_note: false,
      should_skip: true,
    };
  }

  const warningExists = notesStatus.warning_note_already_exists === true;
  const warningOlderOrEqual7Days = notesStatus.has_warning_note_older_or_equal_7_days === true;

  /**
   * NUEVA REGLA:
   * Si el lead ya tiene una warning note creada previamente por la automatización,
   * no se crea otra warning note.
   * Se reasigna inmediatamente al Buyer Reassignment Pond
   * y se crea una nota de reasignación por falta de acción después del warning.
   */
  if (warningExists) {
    return {
      recommended_action: 'S1_REASSIGN_POND',
      action_bucket: 'REASSIGN',
      action_reason: 'Communication is stale and lead already has an automation warning note. Duplicate warning blocked; lead will be reassigned immediately to Buyer Reassignment Pond.',
      should_reassign: true,
      should_create_warning_note: false,
      should_create_reassignment_note: true,
      reassignment_after_warning_note: true,
      reassignment_note_subject: 'n8n reassignment',
      reassignment_note_body: 'Lead reassigned to pond due to no action taken after the warning note.',
      should_skip: false,
    };
  }

  /**
   * Si no hay tareas abiertas, se mantiene la regla previa:
   * stale + zero tasks => reasignación directa.
   */
  if (tasksStatus.has_zero_tasks) {
    return {
      recommended_action: 'S1_REASSIGN_POND',
      action_bucket: 'REASSIGN',
      action_reason: 'Communication is stale and lead has zero open tasks.',
      should_reassign: true,
      should_create_warning_note: false,
      should_skip: false,
    };
  }

  /**
   * Regla confirmada:
   * Si tiene tarea activa/no vencida, NO pasa a pond.
   */
  if (tasksStatus.has_active_nonoverdue_task) {
    return {
      recommended_action: 'NO_ACTION',
      action_bucket: 'NO_ACTION',
      action_reason: 'Communication is stale, but lead has active non-overdue task. No reassignment applied.',
      should_reassign: false,
      should_create_warning_note: false,
      should_skip: true,
    };
  }

  /**
   * Escalación por warning:
   * Solo se reasigna si tiene tarea vencida y warning previo de 7+ días.
   */
  if (tasksStatus.has_overdue_task && warningExists && warningOlderOrEqual7Days) {
    return {
      recommended_action: 'S1_REASSIGN_POND',
      action_bucket: 'REASSIGN',
      action_reason: 'Communication is stale, lead has overdue task, and automation warning note is 7+ days old.',
      should_reassign: true,
      should_create_warning_note: false,
      should_skip: false,
    };
  }

  if (tasksStatus.has_overdue_task && warningExists && !warningOlderOrEqual7Days) {
    return {
      recommended_action: 'NO_ACTION',
      action_bucket: 'NO_ACTION',
      action_reason: 'Communication is stale and lead has overdue task, but existing automation warning note is less than 7 days old. Duplicate warning blocked.',
      should_reassign: false,
      should_create_warning_note: false,
      should_skip: true,
    };
  }

  if (tasksStatus.has_overdue_task && !warningExists) {
    return {
      recommended_action: 'S2_WARNING_NOTE',
      action_bucket: 'WARNING_NOTE',
      action_reason: 'Communication is stale and lead has overdue task. Creating first automation warning note.',
      should_reassign: false,
      should_create_warning_note: true,
      should_skip: false,
    };
  }

  if (tasksStatus.has_open_tasks && warningExists) {
    return {
      recommended_action: 'NO_ACTION',
      action_bucket: 'NO_ACTION',
      action_reason: 'Communication is stale and lead already has automation warning note. Duplicate warning blocked.',
      should_reassign: false,
      should_create_warning_note: false,
      should_skip: true,
    };
  }

  if (tasksStatus.has_open_tasks && !warningExists) {
    return {
      recommended_action: 'S2_WARNING_NOTE',
      action_bucket: 'WARNING_NOTE',
      action_reason: 'Communication is stale and lead has open task not eligible for reassignment. Creating first automation warning note.',
      should_reassign: false,
      should_create_warning_note: true,
      should_skip: false,
    };
  }

  return {
    recommended_action: 'NO_ACTION',
    action_bucket: 'NO_ACTION',
    action_reason: 'Unclassified task/note state. No mutation applied.',
    should_reassign: false,
    should_create_warning_note: false,
    should_skip: true,
  };
}

const records = normalizeInput(items);

const profilesByLeadId = new Map();

function getOrCreateProfile(leadId) {
  if (!profilesByLeadId.has(leadId)) {
    profilesByLeadId.set(leadId, {
      lead_id: leadId,
      lead_base_record: null,
      communication_record: null,
      tasks_record: null,
      notes_record: null,
      source_counts: {
        total_records: 0,
        lead_base_records: 0,
        communication_records: 0,
        tasks_records: 0,
        notes_records: 0,
      },
    });
  }

  return profilesByLeadId.get(leadId);
}

const skippedRecords = [];

for (const record of records) {
  const leadId = getLeadId(record);

  if (!leadId) {
    skippedRecords.push({
      reason: 'missing_lead_id',
      keys: Object.keys(record || {}),
    });
    continue;
  }

  const profile = getOrCreateProfile(leadId);

  profile.source_counts.total_records += 1;

  if (isLeadBaseRecord(record)) {
    profile.lead_base_record = {
      ...(profile.lead_base_record || {}),
      ...record,
    };

    profile.source_counts.lead_base_records += 1;
  }

  if (isCommunicationRecord(record)) {
    profile.communication_record = {
      ...(profile.communication_record || {}),
      ...record,
    };

    profile.source_counts.communication_records += 1;
  }

  if (isTasksRecord(record)) {
    profile.tasks_record = {
      ...(profile.tasks_record || {}),
      ...record,
    };

    profile.source_counts.tasks_records += 1;
  }

  if (isNotesRecord(record)) {
    profile.notes_record = {
      ...(profile.notes_record || {}),
      ...record,
    };

    profile.source_counts.notes_records += 1;
  }
}

const outputProfiles = [];

for (const [leadId, grouped] of profilesByLeadId.entries()) {
  const leadInfo = pickLeadInfo(grouped.lead_base_record);
  const communicationProfile = pickCommunicationProfile(grouped.communication_record);
  const tasksProfile = pickTasksProfile(grouped.tasks_record);
  const notesProfile = pickNotesProfile(grouped.notes_record);

  const communicationStatus = deriveCommunicationStatus(communicationProfile);
  const tasksStatus = deriveTasksStatus(tasksProfile);
  const notesStatus = deriveNotesStatus(notesProfile);
  const actionEligibility = deriveRecommendedAction(communicationStatus, tasksStatus, notesStatus);

  const hasCompleteProfile =
    Boolean(leadInfo) &&
    communicationStatus.communication_status !== 'MISSING_COMMUNICATION_PROFILE' &&
    tasksStatus.tasks_status !== 'MISSING_TASKS_PROFILE' &&
    notesStatus.notes_status !== 'MISSING_NOTES_PROFILE';

  const profileWarnings = [];

  if (!leadInfo) {
    profileWarnings.push('Missing lead base profile.');
  }

  if (communicationStatus.communication_status === 'MISSING_COMMUNICATION_PROFILE') {
    profileWarnings.push('Missing communication profile.');
  }

  if (tasksStatus.tasks_status === 'MISSING_TASKS_PROFILE') {
    profileWarnings.push('Missing tasks profile.');
  }

  if (notesStatus.notes_status === 'MISSING_NOTES_PROFILE') {
    profileWarnings.push('Missing notes profile.');
  }

  if (notesStatus.notes_api_error) {
    profileWarnings.push('Notes API error.');
  }

  outputProfiles.push({
    json: {
      item_type: 'full_lead_profile',

      lead_id: leadId,
      id: leadInfo?.id ?? leadId,

      name: leadInfo?.name ?? '',
      source: leadInfo?.source ?? '',
      created: leadInfo?.created ?? '',

      agent_id: leadInfo?.agent_id ?? null,
      agent_name: leadInfo?.agent_name ?? '',

      pond_id: leadInfo?.pond_id ?? null,
      stage_id: leadInfo?.stage_id ?? null,
      stage: leadInfo?.stage ?? '',

      last_activity: leadInfo?.last_activity ?? null,
      last_activity_iso: leadInfo?.last_activity_iso ?? null,
      days_since_last_activity: leadInfo?.days_since_last_activity ?? null,

      latest_communication_date: communicationStatus.latest_communication_date,
      latest_communication_source: communicationStatus.latest_communication_source,
      days_since_latest_communication: communicationStatus.days_since_latest_communication,
      last_communication_gt_30d: communicationStatus.last_communication_gt_30d,
      communication_status: communicationStatus.communication_status,
      action_candidate_by_communication: communicationStatus.action_candidate_by_communication,

      open_tasks_count: tasksStatus.open_tasks_count,
      overdue_tasks_count: tasksStatus.overdue_tasks_count,
      active_nonoverdue_tasks_count: tasksStatus.active_nonoverdue_tasks_count,
      has_zero_tasks: tasksStatus.has_zero_tasks,
      has_open_tasks: tasksStatus.has_open_tasks,
      has_overdue_task: tasksStatus.has_overdue_task,
      has_active_nonoverdue_task: tasksStatus.has_active_nonoverdue_task,
      has_due_today_task: tasksStatus.has_due_today_task,
      has_future_task: tasksStatus.has_future_task,
      has_no_due_date_task: tasksStatus.has_no_due_date_task,
      tasks_status: tasksStatus.tasks_status,

      notes_profile_found: notesStatus.notes_profile_found,
      notes_api_error: notesStatus.notes_api_error,
      notes_status: notesStatus.notes_status,
      warning_note_already_exists: notesStatus.warning_note_already_exists,
      existing_warning_notes_count: notesStatus.existing_warning_notes_count,
      has_warning_note_older_or_equal_7_days: notesStatus.has_warning_note_older_or_equal_7_days,
      latest_warning_note_id: notesStatus.latest_warning_note_id,
      latest_warning_note_created: notesStatus.latest_warning_note_created,
      latest_warning_note_age_days: notesStatus.latest_warning_note_age_days,
      oldest_warning_note_id: notesStatus.oldest_warning_note_id,
      oldest_warning_note_created: notesStatus.oldest_warning_note_created,
      oldest_warning_note_age_days: notesStatus.oldest_warning_note_age_days,

      recommended_action: actionEligibility.recommended_action,
      action_bucket: actionEligibility.action_bucket,
      action_reason: actionEligibility.action_reason,
      should_reassign: actionEligibility.should_reassign,
      should_create_warning_note: actionEligibility.should_create_warning_note,
      should_create_reassignment_note: actionEligibility.should_create_reassignment_note === true,
      reassignment_after_warning_note: actionEligibility.reassignment_after_warning_note === true,
      reassignment_note_subject: actionEligibility.reassignment_note_subject ?? null,
      reassignment_note_body: actionEligibility.reassignment_note_body ?? null,
      should_skip: actionEligibility.should_skip,

      profile_complete: hasCompleteProfile,
      profile_status: hasCompleteProfile ? 'FULL_PROFILE_READY' : 'PROFILE_INCOMPLETE',
      profile_warnings: profileWarnings,

      source_counts: grouped.source_counts,

      lead_info: leadInfo,
      communication_profile: communicationProfile,
      communication_status_detail: communicationStatus,
      tasks_profile: tasksProfile,
      tasks_status_detail: tasksStatus,
      notes_profile: notesProfile,
      notes_status_detail: notesStatus,
      action_eligibility: actionEligibility,
    },
  });
}

outputProfiles.sort((a, b) => {
  const actionA = a.json.action_bucket || '';
  const actionB = b.json.action_bucket || '';

  const priority = {
    REASSIGN: 1,
    WARNING_NOTE: 2,
    NO_ACTION: 3,
    REVIEW: 4,
  };

  const pA = priority[actionA] ?? 99;
  const pB = priority[actionB] ?? 99;

  if (pA !== pB) return pA - pB;

  return Number(a.json.lead_id) - Number(b.json.lead_id);
});

if (INCLUDE_SUMMARY) {
  const summary = {
    json: {
      item_type: 'summary',
      phase: 'build_full_lead_profile',
      created_at: now.toISOString(),

      input_records: records.length,
      output_profiles: outputProfiles.length,
      skipped_records: skippedRecords.length,

      complete_profiles: outputProfiles.filter(x => x.json.profile_complete).length,
      incomplete_profiles: outputProfiles.filter(x => !x.json.profile_complete).length,

      no_action: outputProfiles.filter(x => x.json.action_bucket === 'NO_ACTION').length,
      reassign_candidates: outputProfiles.filter(x => x.json.action_bucket === 'REASSIGN').length,
      warning_note_candidates: outputProfiles.filter(x => x.json.action_bucket === 'WARNING_NOTE').length,
      review_candidates: outputProfiles.filter(x => x.json.action_bucket === 'REVIEW').length,

      skipped_records_sample: skippedRecords.slice(0, 20),
    },
  };

  return [summary, ...outputProfiles];
}

return outputProfiles;

/****************************************************************************************
 * NODE: EXE Router
 * MODE: Run Once for All Items
 *
 * OBJETIVO:
 * - Recibir el output final de Build Full Lead Profile.
 * - NO recalcular reglas de comunicación, tareas ni notes.
 * - Respetar recommended_action, action_bucket, should_reassign,
 *   should_create_warning_note y should_create_reassignment_note.
 *
 * ACCIONES:
 * - NO_ACTION
 * - S1_REASSIGN_POND
 * - S2_WARNING_NOTE
 *
 * MUTACIONES:
 * - reassign_to_pond
 * - create_warning_note
 * - create_reassignment_note
 *
 * NOTA:
 * - create_reassignment_note conserva mutation_type = note_create porque en FUB
 *   sigue siendo una creación de nota.
 * - La diferencia importante está en action_type, normalized_action_type,
 *   note_type y report_group para que el reporte no la clasifique como warning.
 ****************************************************************************************/

const items = $input.all();

/**
 * Modos disponibles:
 * EXECUTE     => permite ejecutar mutaciones FUB
 * DRY_RUN     => prepara rutas pero no ejecuta FUB
 * REPORT_ONLY => prepara para reporte, no ejecuta FUB
 *
 * Para producción, cambiar a EXECUTE.
 */
// const EXECUTION_MODE = "EXECUTE";
const EXECUTION_MODE = "DRY_RUN";
// const EXECUTION_MODE = "REPORT_ONLY";

const BUYER_REASSIGNMENT_POND_ID = 272;
const BUYER_REASSIGNMENT_POND_NAME = "Buyer Reassignment Pond";

const TAG_TO_ADD = "n8n reassignments";

const FUB_PERSON_URL_BASE = "https://app.followupboss.com/2/people/view/";

const WARNING_NOTE_SUBJECT = "n8n warning";

const WARNING_NOTE_BODY =
  "n8n warning : This lead has not been contacted in 30+ days. Please follow up today or this lead will be reassigned on the next audit";

const REASSIGN_AFTER_WARNING_NOTE_SUBJECT = "n8n reassignment";

const REASSIGN_AFTER_WARNING_NOTE_BODY =
  "Lead reassigned to pond due to no action taken after the warning note.";

function getLeadId(j) {
  return (
    j.lead_id ??
    j.id ??
    j.lead_info?.lead_id ??
    j.lead_info?.id ??
    j.communication_profile?.lead_id ??
    j.tasks_profile?.lead_id ??
    j.notes_profile?.lead_id ??
    null
  );
}

function getLeadName(j) {
  return (
    j.name ??
    j.lead_info?.name ??
    ""
  );
}

function getAgentId(j) {
  return (
    j.agent_id ??
    j.lead_info?.agent_id ??
    null
  );
}

function getAgentName(j) {
  return (
    j.agent_name ??
    j.lead_info?.agent_name ??
    ""
  );
}

function getFubLink(leadId) {
  return leadId ? `${FUB_PERSON_URL_BASE}${leadId}` : null;
}

function getReason(j, fallback = null) {
  return (
    j.action_reason ??
    j.reason ??
    j.action_eligibility?.action_reason ??
    fallback
  );
}

function getExecutionFlags(canExecute) {
  if (!canExecute) {
    return {
      router_action: "skip",
      should_execute_fub: false,
      execution_status: "skipped",
    };
  }

  if (EXECUTION_MODE === "DRY_RUN") {
    return {
      router_action: "dry_run",
      should_execute_fub: false,
      execution_status: "dry_run_ready",
    };
  }

  if (EXECUTION_MODE === "REPORT_ONLY") {
    return {
      router_action: "report_only",
      should_execute_fub: false,
      execution_status: "prepared_report_only",
    };
  }

  return {
    router_action: "execute_fub",
    should_execute_fub: true,
    execution_status: "ready_to_execute",
  };
}

function buildBaseRouteFields(j) {
  const leadId = getLeadId(j);

  return {
    execution_mode: EXECUTION_MODE,

    lead_id: leadId,
    id: j.id ?? leadId,

    name: getLeadName(j),

    agent_id: getAgentId(j),
    agent_name: getAgentName(j),

    fub_lead_url: getFubLink(leadId),

    reason: getReason(j),
    action_reason: getReason(j),

    route_source: "build_full_lead_profile",
  };
}

function routeNoAction(j, reason) {
  const leadId = getLeadId(j);

  return {
    json: {
      ...j,
      ...buildBaseRouteFields(j),

      router_action: "skip",
      should_execute_fub: false,
      execution_status: "skipped",
      execution_message: reason,

      action_type: null,
      normalized_action_type: null,
      mutation_type: null,
      action_key: `${leadId ?? "null"}_no_action`,

      method: null,
      endpoint: null,
      payload: null,

      requires_fresh_tags: false,
      tag_to_add: null,

      destination_pond_id: null,
      destination_pond_name: null,
      reassignment_type: null,

      note_type: null,
      report_action_type: "no_action",
      report_group: "no_action",

      payload_warnings: [],
    },
  };
}

function routeBlocked(j, reason, warningCode = null) {
  const leadId = getLeadId(j);

  return {
    json: {
      ...j,
      ...buildBaseRouteFields(j),

      router_action: "blocked",
      should_execute_fub: false,
      execution_status: "blocked",
      execution_message: reason,

      action_type: null,
      normalized_action_type: null,
      mutation_type: null,
      action_key: `${leadId ?? "null"}_blocked`,

      method: null,
      endpoint: null,
      payload: null,

      requires_fresh_tags: false,
      tag_to_add: null,

      destination_pond_id: null,
      destination_pond_name: null,
      reassignment_type: null,

      note_type: null,
      report_action_type: "blocked",
      report_group: "blocked",

      payload_warnings: warningCode ? [warningCode] : [],
    },
  };
}

function routeReassign(j) {
  const leadId = getLeadId(j);
  const flags = getExecutionFlags(true);

  const reason = getReason(
    j,
    "Lead qualifies for pond reassignment according to full lead profile."
  );

  return {
    json: {
      ...j,
      ...buildBaseRouteFields(j),

      router_action: flags.router_action,
      should_execute_fub: flags.should_execute_fub,
      execution_status: flags.execution_status,
      execution_message: flags.should_execute_fub
        ? "Ready to execute FUB pond reassignment."
        : `Prepared but not executing because mode is ${EXECUTION_MODE}.`,

      action_type: "reassign_to_pond",
      normalized_action_type: "reassign_to_pond",
      mutation_type: "reassign_pond",
      action_key: `${leadId ?? "null"}_reassign_to_pond`,

      method: "PUT",
      endpoint: `/people/${leadId}`,

      payload: {
        personId: leadId,
        id: leadId,
        assignedPondId: BUYER_REASSIGNMENT_POND_ID,
        pondId: BUYER_REASSIGNMENT_POND_ID,
      },

      requires_fresh_tags: true,
      tag_to_add: TAG_TO_ADD,

      destination_pond_id: BUYER_REASSIGNMENT_POND_ID,
      destination_pond_name: BUYER_REASSIGNMENT_POND_NAME,
      reassignment_type: "stale_communication_reassignment",

      reason,
      action_reason: reason,

      note_type: null,
      report_action_type: "reassign_to_pond",
      report_group: "pond_reassignments",

      payload_warnings: [],
    },
  };
}

function routeWarningNote(j) {
  const leadId = getLeadId(j);
  const flags = getExecutionFlags(true);

  const reason = getReason(
    j,
    "Lead qualifies for first automation warning note according to full lead profile."
  );

  return {
    json: {
      ...j,
      ...buildBaseRouteFields(j),

      router_action: flags.router_action,
      should_execute_fub: flags.should_execute_fub,
      execution_status: flags.execution_status,
      execution_message: flags.should_execute_fub
        ? "Ready to execute FUB warning note."
        : `Prepared but not executing because mode is ${EXECUTION_MODE}.`,

      action_type: "create_warning_note",
      normalized_action_type: "create_warning_note",
      mutation_type: "note_create",
      action_key: `${leadId ?? "null"}_create_warning_note`,

      method: "POST",
      endpoint: "/notes",

      payload: {
        personId: leadId,
        leadId,
        subject: WARNING_NOTE_SUBJECT,
        note: WARNING_NOTE_BODY,
        body: WARNING_NOTE_BODY,
        isHtml: false,
      },

      requires_fresh_tags: false,
      tag_to_add: null,

      destination_pond_id: null,
      destination_pond_name: null,
      reassignment_type: null,

      reason,
      action_reason: reason,

      note_type: "warning_note",
      report_action_type: "create_warning_note",
      report_group: "warning_notes",

      warning_note_subject: WARNING_NOTE_SUBJECT,
      warning_note_body: WARNING_NOTE_BODY,

      payload_warnings: [],
    },
  };
}

function shouldCreateReassignmentAfterWarningNote(j) {
  return (
    j.reassignment_after_warning_note === true ||
    j.should_create_reassignment_note === true ||
    j.action_eligibility?.reassignment_after_warning_note === true ||
    j.action_eligibility?.should_create_reassignment_note === true
  );
}

function routeReassignmentAfterWarningNote(j) {
  const leadId = getLeadId(j);
  const flags = getExecutionFlags(true);

  const noteSubject =
    j.reassignment_note_subject ||
    j.action_eligibility?.reassignment_note_subject ||
    REASSIGN_AFTER_WARNING_NOTE_SUBJECT;

  const noteBody =
    j.reassignment_note_body ||
    j.action_eligibility?.reassignment_note_body ||
    REASSIGN_AFTER_WARNING_NOTE_BODY;

  const reason =
    "Lead was reassigned to pond because it already had an automation warning note and no action was taken.";

  return {
    json: {
      ...j,
      ...buildBaseRouteFields(j),

      router_action: flags.router_action,
      should_execute_fub: flags.should_execute_fub,
      execution_status: flags.execution_status,
      execution_message: flags.should_execute_fub
        ? "Ready to execute FUB reassignment note."
        : `Prepared but not executing because mode is ${EXECUTION_MODE}.`,

      /**
       * Sigue siendo note_create porque FUB crea una nota.
       * Pero ya NO se clasifica como warning note.
       */
      action_type: "create_reassignment_note",
      normalized_action_type: "create_reassignment_note",
      mutation_type: "note_create",
      action_key: `${leadId ?? "null"}_reassign_after_warning_note`,

      method: "POST",
      endpoint: "/notes",

      payload: {
        personId: leadId,
        leadId,
        subject: noteSubject,
        note: noteBody,
        body: noteBody,
        isHtml: false,
      },

      requires_fresh_tags: false,
      tag_to_add: null,

      destination_pond_id: null,
      destination_pond_name: null,
      reassignment_type: "reassignment_after_warning",

      reason,
      action_reason: reason,

      note_type: "reassignment_after_warning",
      report_action_type: "create_reassignment_note",
      report_group: "reassignment_notes",

      reassignment_note_subject: noteSubject,
      reassignment_note_body: noteBody,

      /**
       * Campo de compatibilidad por si algún nodo posterior todavía revisa
       * si esto es una note_create. No debe usarse para clasificarlo como warning.
       */
      legacy_note_create_action: "create_warning_note",

      payload_warnings: [],
    },
  };
}

function isNoAction(j) {
  return (
    j.should_skip === true ||
    j.recommended_action === "NO_ACTION" ||
    j.action_bucket === "NO_ACTION"
  );
}

function isReassign(j) {
  return (
    j.recommended_action === "S1_REASSIGN_POND" ||
    j.should_reassign === true ||
    j.action_bucket === "REASSIGN" ||
    j.action_bucket === "REASSIGN_POND"
  );
}

function isWarningNote(j) {
  return (
    j.recommended_action === "S2_WARNING_NOTE" ||
    j.should_create_warning_note === true ||
    j.action_bucket === "WARNING_NOTE"
  );
}

const output = [];

for (const item of items) {
  const j = item.json || {};
  const leadId = getLeadId(j);

  if (!leadId) {
    output.push(
      routeBlocked(
        j,
        "Missing lead_id. No FUB mutation allowed.",
        "missing_lead_id"
      )
    );

    continue;
  }

  /**
   * Seguridad:
   * Si Build Full Lead Profile marcó perfil incompleto, no ejecuta mutaciones.
   */
  if (j.profile_complete === false) {
    output.push(
      routeNoAction(
        j,
        getReason(j, "Profile incomplete. No FUB mutation allowed.")
      )
    );

    continue;
  }

  /**
   * Seguridad:
   * Si Notes API falló, no ejecuta mutaciones.
   */
  if (j.notes_api_error === true || j.notes_status === "NOTES_API_ERROR") {
    output.push(
      routeNoAction(
        j,
        getReason(j, "Notes API error. No FUB mutation allowed.")
      )
    );

    continue;
  }

  /**
   * NO_ACTION:
   * Incluye casos con comunicación reciente, tarea activa/no vencida
   * o cualquier skip decidido antes.
   */
  if (isNoAction(j)) {
    output.push(
      routeNoAction(
        j,
        getReason(j, "No action required according to full lead profile.")
      )
    );

    continue;
  }

  /**
   * S1_REASSIGN_POND:
   * Si además existe reassignment_after_warning_note,
   * se generan dos items:
   * 1. reassign_to_pond
   * 2. create_reassignment_note
   */
  if (isReassign(j)) {
    output.push(routeReassign(j));

    if (shouldCreateReassignmentAfterWarningNote(j)) {
      output.push(routeReassignmentAfterWarningNote(j));
    }

    continue;
  }

  /**
   * S2_WARNING_NOTE:
   * Primera warning note.
   */
  if (isWarningNote(j)) {
    output.push(routeWarningNote(j));
    continue;
  }

  /**
   * Cualquier estado no reconocido queda bloqueado.
   */
  output.push(
    routeBlocked(
      j,
      `Unsupported recommended_action: ${j.recommended_action ?? "missing"}`,
      `unsupported_recommended_action:${j.recommended_action ?? "missing"}`
    )
  );
}

return output;

/****************************************************************************************
 * NODE: Prepare FUB Mutations
 * MODE: Run Once for All Items
 *
 * OBJETIVO:
 * - Recibir output de EXE Router.
 * - Preparar mutaciones reales para FUB.
 * - No recalcular lógica de negocio.
 * - Respetar recommended_action, action_type, mutation_type y should_execute_fub.
 *
 * MUTACIONES PERMITIDAS:
 * - reassign_to_pond / reassign_pond
 * - create_warning_note / note_create
 * - create_reassignment_note / note_create
 *
 * BLOQUEADAS:
 * - stage_change
 * - update_stage
 * - task_create
 * - create_task
 * - payloads incompletos
 * - endpoints no permitidos
 * - duplicados por lead_id + mutation_type/action_type
 *
 * REGLAS:
 * - NO_ACTION / skipped / blocked no preparan mutación.
 * - Reassign debe pasar por Fresh Lead Tags + Reassign Body.
 * - Note Create va directo a FUB Create Note.
 * - No se cambia Stage.
 * - No se crean Tasks.
 *
 * FIX IMPORTANTE:
 * - create_reassignment_note ahora es permitido.
 * - mutation_type sigue siendo note_create.
 * - action_type NO debe volver a create_warning_note cuando note_type sea
 *   reassignment_after_warning.
 ****************************************************************************************/

const items = $input.all();

const FUB_BASE_URL = "https://api.followupboss.com/v1";

const DEFAULT_WARNING_SUBJECT = "n8n warning";

const DEFAULT_WARNING_BODY =
  "n8n warning : This lead has not been contacted in 30+ days. Please follow up today or this lead will be reassigned on the next audit";

const DEFAULT_REASSIGNMENT_NOTE_SUBJECT = "n8n reassignment";

const DEFAULT_REASSIGNMENT_NOTE_BODY =
  "Lead reassigned to pond due to no action taken after the warning note.";

const DEFAULT_DESTINATION_POND_ID = 272;
const DEFAULT_DESTINATION_POND_NAME = "Buyer Reassignment Pond";

const TAG_TO_ADD = "n8n reassignments";

const ALLOWED_MUTATION_TYPES = new Set([
  "reassign_pond",
  "note_create",
]);

const ALLOWED_ACTION_TYPES = new Set([
  "reassign_to_pond",
  "create_warning_note",
  "create_reassignment_note",
]);

const BLOCKED_ACTION_TYPES = new Set([
  "update_stage",
  "create_task",
  "stage_change",
  "task_create",
]);

function isNonEmptyString(value) {
  return typeof value === "string" && value.trim().length > 0;
}

function isPositiveNumber(value) {
  const num = Number(value);
  return Number.isFinite(num) && num > 0;
}

function firstValidNumber(values) {
  for (const value of values) {
    const num = Number(value);
    if (Number.isFinite(num) && num > 0) {
      return num;
    }
  }

  return null;
}

function safeString(value, fallback = "") {
  if (value === undefined || value === null) return String(fallback);
  return String(value);
}

function safeTrim(value, fallback = "") {
  return safeString(value, fallback).trim();
}

function isReassignmentAfterWarning(j) {
  const actionKey = safeTrim(j.action_key);

  return (
    j.note_type === "reassignment_after_warning" ||
    j.report_group === "reassignment_notes" ||
    j.report_action_type === "create_reassignment_note" ||
    j.action_type === "create_reassignment_note" ||
    j.normalized_action_type === "create_reassignment_note" ||
    j.reassignment_type === "reassignment_after_warning" ||
    j.reassignment_after_warning_note === true ||
    j.should_create_reassignment_note === true ||
    j.action_eligibility?.reassignment_after_warning_note === true ||
    j.action_eligibility?.should_create_reassignment_note === true ||
    actionKey.includes("reassign_after_warning_note")
  );
}

function normalizeActionTypeFromItem(j) {
  const clean = safeTrim(
    j.normalized_action_type ||
    j.action_type ||
    j.mutation_type
  );

  if (clean === "reassign_to_pond") return "reassign_to_pond";
  if (clean === "reassign_pond") return "reassign_to_pond";

  if (clean === "create_reassignment_note") return "create_reassignment_note";

  if (clean === "create_warning_note") return "create_warning_note";

  if (clean === "note_create") {
    return isReassignmentAfterWarning(j)
      ? "create_reassignment_note"
      : "create_warning_note";
  }

  return clean || null;
}

function normalizeActionType(value) {
  const clean = safeTrim(value);

  if (clean === "reassign_to_pond") return "reassign_to_pond";
  if (clean === "reassign_pond") return "reassign_to_pond";

  if (clean === "create_warning_note") return "create_warning_note";
  if (clean === "create_reassignment_note") return "create_reassignment_note";

  if (clean === "note_create") return "create_warning_note";

  return clean || null;
}

function normalizeMutationType(j) {
  const mutationType = safeTrim(j.mutation_type);
  const actionType = normalizeActionTypeFromItem(j);

  if (mutationType === "reassign_pond") return "reassign_pond";
  if (mutationType === "note_create") return "note_create";

  if (actionType === "reassign_to_pond") return "reassign_pond";

  if (
    actionType === "create_warning_note" ||
    actionType === "create_reassignment_note"
  ) {
    return "note_create";
  }

  return mutationType || null;
}

function getLeadId(j) {
  return firstValidNumber([
    j.lead_id,
    j.id,
    j.personId,
    j.person_id,
    j.payload?.personId,
    j.payload?.leadId,
    j.payload?.id,
    j.lead_info?.lead_id,
    j.lead_info?.id,
  ]);
}

function getPayload(j) {
  if (j.payload && typeof j.payload === "object") {
    return j.payload;
  }

  if (j.body && typeof j.body === "object") {
    return j.body;
  }

  return {};
}

function getReason(j) {
  return (
    j.action_reason ||
    j.reason ||
    j.action_eligibility?.action_reason ||
    null
  );
}

function getExecutionMode(j) {
  return safeTrim(j.execution_mode || "EXECUTE");
}

function shouldExecute(j) {
  return j.should_execute_fub === true;
}

function getBaseOutput(j) {
  const leadId = getLeadId(j);

  return {
    ...j,

    lead_id: j.lead_id ?? leadId,
    id: j.id ?? leadId,

    reason: getReason(j),
    action_reason: getReason(j),

    prepare_fub_mutations_processed: true,
    prepared_at: new Date().toISOString(),
  };
}

function buildBlocked(j, warnings = []) {
  const leadId = getLeadId(j);
  const mutationType = normalizeMutationType(j);
  const actionType = normalizeActionTypeFromItem(j);

  return {
    json: {
      ...getBaseOutput(j),

      mutation_prepared: false,
      mutation_allowed: false,
      mutation_type: mutationType,
      action_type: actionType,
      normalized_action_type: actionType,

      execute_fub_changes: false,
      should_execute_fub: false,

      prepare_execution_status: "blocked",
      execution_status: j.execution_status || "blocked",
      execution_message:
        j.execution_message ||
        "Mutation blocked in Prepare FUB Mutations.",

      request_method: null,
      method: null,
      endpoint: null,
      request_url: null,
      body: null,

      fresh_tags_url: null,
      requires_fresh_tags: false,
      fresh_tags_required: false,

      prepare_warnings: warnings,
      prepare_error: warnings.join("|") || "mutation_blocked",

      action_key:
        j.action_key ||
        `${leadId ?? "null"}_${mutationType || actionType || "blocked"}`,
    },
  };
}

function buildSkipped(j, reason = "Skipped item. No FUB mutation prepared.") {
  const leadId = getLeadId(j);
  const mutationType = normalizeMutationType(j);
  const actionType = normalizeActionTypeFromItem(j);

  return {
    json: {
      ...getBaseOutput(j),

      mutation_prepared: false,
      mutation_allowed: false,
      mutation_type: mutationType,
      action_type: actionType,
      normalized_action_type: actionType,

      execute_fub_changes: false,
      should_execute_fub: false,

      prepare_execution_status: "skipped",
      execution_status: j.execution_status || "skipped",
      execution_message: reason,

      request_method: null,
      method: null,
      endpoint: null,
      request_url: null,
      body: null,

      fresh_tags_url: null,
      requires_fresh_tags: false,
      fresh_tags_required: false,

      prepare_warnings: [],
      prepare_error: null,

      action_key:
        j.action_key ||
        `${leadId ?? "null"}_${mutationType || actionType || "skipped"}`,
    },
  };
}

function buildReady(
  j,
  mutationType,
  requestUrl,
  body,
  requiresFreshTags = false,
  freshTagsUrl = null,
  actionTypeOverride = null
) {
  const leadId = getLeadId(j);
  const executionMode = getExecutionMode(j);
  const canExecute = shouldExecute(j);

  const actionType =
    actionTypeOverride ||
    normalizeActionTypeFromItem(j) ||
    (
      mutationType === "reassign_pond"
        ? "reassign_to_pond"
        : "create_warning_note"
    );

  const method =
    mutationType === "reassign_pond"
      ? "PUT"
      : mutationType === "note_create"
        ? "POST"
        : j.method || null;

  const isReassignmentNote = actionType === "create_reassignment_note";

  return {
    json: {
      ...getBaseOutput(j),

      mutation_prepared: true,
      mutation_allowed: true,
      mutation_type: mutationType,

      action_type: actionType,
      normalized_action_type: actionType,

      execute_fub_changes: canExecute,
      should_execute_fub: canExecute,

      prepare_execution_status: canExecute
        ? "ready_to_execute"
        : "prepared_not_executing",

      execution_status: canExecute
        ? "ready_to_execute"
        : j.execution_status || "prepared_not_executing",

      execution_message: canExecute
        ? "Mutation prepared and ready for FUB execution."
        : `Mutation prepared but not executing. execution_mode=${executionMode}.`,

      request_method: method,
      method,

      endpoint:
        mutationType === "reassign_pond"
          ? `/people/${leadId}`
          : mutationType === "note_create"
            ? "/notes"
            : j.endpoint || null,

      request_url: requestUrl,
      body,

      payload: j.payload || body,

      requires_fresh_tags: requiresFreshTags,
      fresh_tags_required: requiresFreshTags,
      fresh_tags_url: freshTagsUrl,

      destination_pond_id:
        mutationType === "reassign_pond"
          ? (
              j.destination_pond_id ||
              body.assignedPondId ||
              DEFAULT_DESTINATION_POND_ID
            )
          : null,

      destination_pond_name:
        mutationType === "reassign_pond"
          ? (
              j.destination_pond_name ||
              DEFAULT_DESTINATION_POND_NAME
            )
          : null,

      tag_to_add:
        requiresFreshTags
          ? (j.tag_to_add || TAG_TO_ADD)
          : null,

      /**
       * Campos explícitos para reporte.
       */
      note_type:
        mutationType === "note_create"
          ? (
              isReassignmentNote
                ? "reassignment_after_warning"
                : "warning_note"
            )
          : null,

      report_action_type:
        mutationType === "reassign_pond"
          ? "reassign_to_pond"
          : (
              isReassignmentNote
                ? "create_reassignment_note"
                : "create_warning_note"
            ),

      report_group:
        mutationType === "reassign_pond"
          ? "pond_reassignments"
          : (
              isReassignmentNote
                ? "reassignment_notes"
                : "warning_notes"
            ),

      prepare_warnings: [],
      prepare_error: null,

      action_key:
        j.action_key ||
        `${leadId ?? "null"}_${actionType}`,
    },
  };
}

function validateCommon(j, mutationType, actionType, leadId, payload) {
  const warnings = [];

  if (!leadId) {
    warnings.push("missing_lead_id");
  }

  if (!mutationType) {
    warnings.push("missing_mutation_type");
  }

  if (actionType && BLOCKED_ACTION_TYPES.has(actionType)) {
    warnings.push(`blocked_action_type:${actionType}`);
  }

  if (mutationType && !ALLOWED_MUTATION_TYPES.has(mutationType)) {
    warnings.push(`mutation_type_not_allowed:${mutationType}`);
  }

  if (actionType && !ALLOWED_ACTION_TYPES.has(actionType)) {
    warnings.push(`action_type_not_allowed:${actionType}`);
  }

  if (!payload || typeof payload !== "object") {
    warnings.push("missing_payload");
  }

  return warnings;
}

const output = [];
const seenActionKeys = new Set();

for (const item of items) {
  const j = item.json || {};

  const leadId = getLeadId(j);
  const payload = getPayload(j);

  const actionType = normalizeActionTypeFromItem(j);
  const mutationType = normalizeMutationType(j);

  const routerAction = safeTrim(j.router_action);
  const executionStatus = safeTrim(j.execution_status);

  /**
   * NO_ACTION / skip / blocked:
   * No prepara mutación.
   */
  if (
    j.should_skip === true ||
    j.recommended_action === "NO_ACTION" ||
    j.action_bucket === "NO_ACTION" ||
    routerAction === "skip" ||
    routerAction === "blocked" ||
    executionStatus === "skipped" ||
    executionStatus === "blocked"
  ) {
    output.push(
      buildSkipped(
        j,
        j.execution_message ||
          getReason(j) ||
          "No action item. No FUB mutation prepared."
      )
    );

    continue;
  }

  const commonWarnings = validateCommon(
    j,
    mutationType,
    actionType,
    leadId,
    payload
  );

  if (commonWarnings.length > 0) {
    output.push(buildBlocked(j, commonWarnings));
    continue;
  }

  const actionKey =
    j.action_key ||
    `${leadId}_${actionType || mutationType}`;

  /**
   * Evita duplicados dentro de la misma ejecución.
   */
  if (seenActionKeys.has(actionKey)) {
    output.push(
      buildBlocked(j, [
        `duplicate_action_key:${actionKey}`,
      ])
    );

    continue;
  }

  seenActionKeys.add(actionKey);

  /**
   * REASSIGN POND
   *
   * Esta mutación NO debe ejecutarse directamente todavía.
   * Se prepara para pasar por:
   *   Fresh Lead Tags → Merge6 → Reassign Body → Loop → FUB Reassign
   *
   * Por eso body inicial incluye assignedPondId, pero el body final con tags
   * lo construye Reassign Body.
   */
  if (mutationType === "reassign_pond") {
    const personId = firstValidNumber([
      payload.personId,
      payload.id,
      leadId,
    ]);

    const assignedPondId = firstValidNumber([
      payload.assignedPondId,
      payload.pondId,
      j.destination_pond_id,
      DEFAULT_DESTINATION_POND_ID,
    ]);

    const warnings = [];

    if (!personId) {
      warnings.push("missing_personId_for_reassign");
    }

    if (!assignedPondId) {
      warnings.push("missing_assignedPondId_for_reassign");
    }

    if (warnings.length > 0) {
      output.push(buildBlocked(j, warnings));
      continue;
    }

    const body = {
      personId: Number(personId),
      assignedPondId: Number(assignedPondId),
      tags: Array.isArray(payload.tags) ? payload.tags : [],
    };

    output.push(
      buildReady(
        {
          ...j,
          lead_id: personId,
          id: personId,
          destination_pond_id: Number(assignedPondId),
          destination_pond_name:
            j.destination_pond_name || DEFAULT_DESTINATION_POND_NAME,
          requires_fresh_tags: true,
          tag_to_add: j.tag_to_add || TAG_TO_ADD,
        },
        "reassign_pond",
        `${FUB_BASE_URL}/people/${personId}`,
        body,
        true,
        `${FUB_BASE_URL}/people/${personId}`,
        "reassign_to_pond"
      )
    );

    continue;
  }

  /**
   * CREATE NOTE
   *
   * Esta mutación sí va directo a:
   *   FUB Create Note
   *
   * Puede ser:
   * - create_warning_note
   * - create_reassignment_note
   */
  if (mutationType === "note_create") {
    const personId = firstValidNumber([
      payload.personId,
      payload.leadId,
      leadId,
    ]);

    const isReassignmentNote =
      actionType === "create_reassignment_note" ||
      isReassignmentAfterWarning(j);

    const finalActionType = isReassignmentNote
      ? "create_reassignment_note"
      : "create_warning_note";

    const defaultSubject = isReassignmentNote
      ? DEFAULT_REASSIGNMENT_NOTE_SUBJECT
      : DEFAULT_WARNING_SUBJECT;

    const defaultBody = isReassignmentNote
      ? DEFAULT_REASSIGNMENT_NOTE_BODY
      : DEFAULT_WARNING_BODY;

    const noteSubject =
      isNonEmptyString(payload.subject)
        ? String(payload.subject).trim()
        : isNonEmptyString(j.reassignment_note_subject)
          ? String(j.reassignment_note_subject).trim()
          : isNonEmptyString(j.warning_note_subject)
            ? String(j.warning_note_subject).trim()
            : defaultSubject;

    const noteBody =
      isNonEmptyString(payload.body)
        ? String(payload.body)
        : isNonEmptyString(payload.note)
          ? String(payload.note)
          : isNonEmptyString(j.reassignment_note_body)
            ? String(j.reassignment_note_body)
            : isNonEmptyString(j.warning_note_body)
              ? String(j.warning_note_body)
              : defaultBody;

    const warnings = [];

    if (!personId) {
      warnings.push("missing_personId_for_note");
    }

    if (!isNonEmptyString(noteBody)) {
      warnings.push("missing_note_body");
    }

    if (!isNonEmptyString(noteSubject)) {
      warnings.push("missing_note_subject");
    }

    if (warnings.length > 0) {
      output.push(buildBlocked(j, warnings));
      continue;
    }

    const body = {
      personId: Number(personId),
      subject: noteSubject,
      body: noteBody,
      isHtml: payload.isHtml === true,
    };

    const enrichedItem = {
      ...j,
      lead_id: personId,
      id: personId,

      action_type: finalActionType,
      normalized_action_type: finalActionType,

      note_type: isReassignmentNote
        ? "reassignment_after_warning"
        : "warning_note",

      report_action_type: finalActionType,

      report_group: isReassignmentNote
        ? "reassignment_notes"
        : "warning_notes",

      warning_note_subject: isReassignmentNote
        ? j.warning_note_subject
        : noteSubject,

      warning_note_body: isReassignmentNote
        ? j.warning_note_body
        : noteBody,

      reassignment_note_subject: isReassignmentNote
        ? noteSubject
        : j.reassignment_note_subject,

      reassignment_note_body: isReassignmentNote
        ? noteBody
        : j.reassignment_note_body,

      reassignment_type: isReassignmentNote
        ? "reassignment_after_warning"
        : j.reassignment_type,
    };

    output.push(
      buildReady(
        enrichedItem,
        "note_create",
        `${FUB_BASE_URL}/notes`,
        body,
        false,
        null,
        finalActionType
      )
    );

    continue;
  }

  output.push(
    buildBlocked(j, [
      `unhandled_mutation_type:${mutationType || "missing"}`,
    ])
  );
}

return output;

/****************************************************************************************
 * NODE: Reassign Body
 * MODE: Run Once for All Items
 *
 * Prepara el body final para reassign_pond usando tags frescos.
 * Regla no negociable: preservar todos los tags existentes y agregar solo
 * "n8n reassignments" si no existe. No cambia stage ni crea tasks.
 ****************************************************************************************/

const items = $input.all();
const TAG_TO_ADD = "n8n reassignments";

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function uniqueTags(tags) {
  return [...new Set(
    tags
      .filter(tag => typeof tag === "string")
      .map(tag => tag.trim())
      .filter(Boolean)
  )];
}

function firstValidNumber(values) {
  for (const value of values) {
    const num = Number(value);
    if (Number.isFinite(num) && num > 0) return num;
  }
  return null;
}

function getFreshResponse(j) {
  // Fresh Lead Tags may be fullResponse: { statusCode, body }
  if (j.body && typeof j.body === 'object' && (j.body.id || Array.isArray(j.body.tags))) {
    return j.body;
  }
  // If fullResponse body overwrote original body, payload usually remains from original side of Merge.
  if (j.fub_fresh_person && typeof j.fub_fresh_person === 'object') return j.fub_fresh_person;
  return j;
}

const output = items.map((item) => {
  const j = item.json || {};
  const fresh = getFreshResponse(j);

  const personId = firstValidNumber([
    j.lead_id,
    j.id,
    j.personId,
    j.payload?.personId,
    j.body?.personId,
    fresh.id,
    fresh.personId,
  ]);

  const assignedPondId = firstValidNumber([
    j.destination_pond_id,
    j.payload?.assignedPondId,
    j.body?.assignedPondId,
  ]);

  const freshTags = uniqueTags([
    ...asArray(fresh.tags),
    ...asArray(j.fresh_tags),
    ...asArray(j.fub_fresh_tags),
    ...asArray(j.tags),
    ...asArray(j.payload?.tags),
  ]);

  const finalTags = freshTags.includes(TAG_TO_ADD)
    ? freshTags
    : uniqueTags([...freshTags, TAG_TO_ADD]);

  const finalBody = {
    assignedPondId,
    tags: finalTags,
  };

  const warnings = [];
  if (!personId) warnings.push('missing_personId');
  if (!assignedPondId) warnings.push('missing_assignedPondId');
  if (!Array.isArray(fresh.tags) && !Array.isArray(j.tags)) warnings.push('fresh_tags_missing_using_available_tags');
  if (!finalTags.includes(TAG_TO_ADD)) warnings.push(`required_tag_missing:${TAG_TO_ADD}`);

  return {
    json: {
      ...j,
      lead_id: j.lead_id ?? personId,
      id: j.id ?? personId,
      personId,

      body: finalBody,
      payload: finalBody,

      fresh_tags: freshTags,
      final_tags: finalTags,
      fresh_tags_count: freshTags.length,
      final_tags_count: finalTags.length,
      tag_to_add: TAG_TO_ADD,
      n8n_reassignments_added: !freshTags.includes(TAG_TO_ADD),

      fresh_reassign_body_prepared: true,
      fresh_reassign_body_warnings: warnings,

      mutation_type: 'reassign_pond',
      method: 'PUT',
      endpoint: `/people/${personId}`,
      request_url: `https://api.followupboss.com/v1/people/${personId}`,
    },
  };
});

return output;

/****************************************************************************************
 * NODE: Build Planned Changes Report
 * MODE: Run Once for All Items
 *
 * OBJETIVO:
 * - Reportar cambios planeados desde Prepare FUB Mutations.
 * - No recalcular lógica de negocio.
 * - No ejecutar FUB.
 * - Construir:
 *   1) planned_changes_summary
 *   2) planned_change_row
 *
 * CAMBIOS SOPORTADOS:
 * - reassign_to_pond / reassign_pond
 * - create_warning_note / note_create
 * - create_reassignment_note / note_create
 *
 * FIX:
 * - El input real trae action_type = "reassign_to_pond", no "reassign_pond".
 * - El input real trae action_type = "create_reassignment_note" para notas
 *   posteriores a warning.
 * - En DRY_RUN, should_execute_fub=false es correcto, pero el cambio igual
 *   debe aparecer como planned change si mutation_prepared=true y
 *   mutation_allowed=true.
 ****************************************************************************************/

const items = $input.all();

const now = new Date().toISOString();

const ALLOWED_ACTIONS = new Set([
  "reassign_to_pond",
  "reassign_pond",
  "create_warning_note",
  "create_reassignment_note",
  "note_create",
]);

const PROHIBITED_ACTIONS = new Set([
  "update_stage",
  "create_task",
  "stage_change",
  "task_create",
]);

function inc(obj, key) {
  const k = key || "unknown";
  obj[k] = (obj[k] || 0) + 1;
}

function safeString(value, fallback = "") {
  if (value === undefined || value === null) return String(fallback);
  return String(value);
}

function safeTrim(value, fallback = "") {
  return safeString(value, fallback).trim();
}

function firstNonEmpty(...values) {
  for (const value of values) {
    const clean = safeTrim(value);
    if (clean !== "") return clean;
  }

  return "";
}

function isReassignmentNote(j) {
  const actionKey = safeTrim(j.action_key);

  return (
    j.note_type === "reassignment_after_warning" ||
    j.report_group === "reassignment_notes" ||
    j.report_action_type === "create_reassignment_note" ||
    j.action_type === "create_reassignment_note" ||
    j.normalized_action_type === "create_reassignment_note" ||
    j.reassignment_type === "reassignment_after_warning" ||
    j.reassignment_after_warning_note === true ||
    j.should_create_reassignment_note === true ||
    j.action_eligibility?.reassignment_after_warning_note === true ||
    j.action_eligibility?.should_create_reassignment_note === true ||
    actionKey.includes("reassign_after_warning_note")
  );
}

function isWarningBasedReassignment(j) {
  const actionKey = safeTrim(j.action_key);
  const reasonText = firstNonEmpty(
    j.reason,
    j.action_reason,
    j.reassignment_reason,
    j.action_eligibility?.action_reason
  ).toLowerCase();

  return (
    j.reassignment_rule_type === "warning_based" ||
    j.reassignment_category === "warning_based" ||
    j.warning_based_reassignment === true ||
    j.is_warning_based_reassignment === true ||
    j.reassignment_after_warning_note === true ||
    j.should_create_reassignment_note === true ||
    j.action_eligibility?.reassignment_after_warning_note === true ||
    j.action_eligibility?.should_create_reassignment_note === true ||
    actionKey.includes("reassign_after_warning_note") ||
    (
      reasonText.includes("automation warning note") &&
      (
        reasonText.includes("duplicate warning") ||
        reasonText.includes("already has") ||
        reasonText.includes("already had") ||
        reasonText.includes("no action")
      )
    )
  );
}

function normalizeActionType(j) {
  const raw = firstNonEmpty(
    j.report_action_type,
    j.normalized_action_type,
    j.action_type,
    j.mutation_type
  );

  if (raw === "reassign_pond") return "reassign_to_pond";
  if (raw === "reassign_to_pond") return "reassign_to_pond";

  if (raw === "create_reassignment_note") return "create_reassignment_note";

  if (raw === "create_warning_note") return "create_warning_note";

  if (raw === "note_create") {
    return isReassignmentNote(j)
      ? "create_reassignment_note"
      : "create_warning_note";
  }

  return raw || null;
}

function normalizeMutationType(j, actionType) {
  const rawMutation = safeTrim(j.mutation_type);

  if (rawMutation === "reassign_pond") return "reassign_pond";
  if (rawMutation === "note_create") return "note_create";

  if (actionType === "reassign_to_pond") return "reassign_pond";

  if (
    actionType === "create_warning_note" ||
    actionType === "create_reassignment_note"
  ) {
    return "note_create";
  }

  return rawMutation || null;
}

function getTransformationName(actionType) {
  if (actionType === "reassign_to_pond") return "Reassign Pond";
  if (actionType === "create_warning_note") return "Create Warning Note";
  if (actionType === "create_reassignment_note") return "Create Reassignment Note";
  return "Unknown";
}

function getReportGroup(actionType, j) {
  if (j.report_group) return j.report_group;

  if (actionType === "reassign_to_pond") return "pond_reassignments";
  if (actionType === "create_warning_note") return "warning_notes";
  if (actionType === "create_reassignment_note") return "reassignment_notes";

  return "unknown";
}

function getNoteType(actionType, j) {
  if (actionType === "create_reassignment_note") return "reassignment_after_warning";
  if (actionType === "create_warning_note") return "warning_note";

  return j.note_type || null;
}

function getReason(j) {
  return firstNonEmpty(
    j.reason,
    j.action_reason,
    j.reassignment_reason,
    j.warning_reason,
    j.reassignment_note_reason,
    j.action_eligibility?.action_reason
  );
}

function getLeadUrl(j) {
  const leadId = firstNonEmpty(j.lead_id, j.id, j.personId, j.person_id);

  return firstNonEmpty(
    j.fub_lead_url,
    j.link_fub_lead,
    leadId ? `https://app.followupboss.com/2/people/view/${leadId}` : ""
  );
}

function getPlannedBody(j) {
  if (j.body && typeof j.body === "object") return j.body;
  if (j.payload && typeof j.payload === "object") return j.payload;
  if (j.planned_body && typeof j.planned_body === "object") return j.planned_body;

  return null;
}

function isSkippedOrNoAction(j) {
  return (
    j.should_skip === true ||
    j.recommended_action === "NO_ACTION" ||
    j.action_bucket === "NO_ACTION" ||
    j.router_action === "skip" ||
    j.router_action === "blocked" ||
    j.execution_status === "skipped" ||
    j.execution_status === "blocked" ||
    j.prepare_execution_status === "skipped" ||
    j.prepare_execution_status === "blocked"
  );
}

function isPreparedPlannedChange(j, actionType, mutationType) {
  if (!actionType) return false;

  if (PROHIBITED_ACTIONS.has(actionType)) return false;

  if (!ALLOWED_ACTIONS.has(actionType)) return false;

  /**
   * Main rule:
   * Prepared mutations must appear in the report even in DRY_RUN.
   */
  if (j.mutation_prepared === true && j.mutation_allowed === true) {
    return true;
  }

  /**
   * Compatibility fallback:
   * If a previous node does not provide mutation_prepared,
   * still allow clearly prepared DRY_RUN / report rows.
   */
  if (
    j.mutation_prepared === undefined &&
    j.mutation_allowed === undefined &&
    (
      j.router_action === "dry_run" ||
      j.execution_status === "dry_run_ready" ||
      j.prepare_execution_status === "prepared_not_executing" ||
      j.prepare_execution_status === "ready_to_execute"
    ) &&
    mutationType
  ) {
    return true;
  }

  return false;
}

const summary = {
  item_type: "planned_changes_summary",
  report_built_at: now,

  execution_mode: items[0]?.json?.execution_mode || null,

  total_router_items: items.length,
  total_planned_changes: 0,
  total_skipped_items: 0,

  planned_reassign_pond: 0,
  planned_standard_reassign_pond: 0,
  planned_warning_based_reassign_pond: 0,
  planned_warning_notes: 0,
  planned_reassignment_notes: 0,
  planned_note_create: 0,

  should_execute_fub_count: 0,

  prohibited_actions_found: 0,
  blocked_actions_found: 0,

  execution_success_count: 0,
  execution_failed_count: 0,
  execution_rate_limited_count: 0,

  by_action_type: {},
  by_mutation_type: {},
  by_router_action: {},
  by_prepare_execution_status: {},
  by_report_group: {},
  by_execution_status: {},
  by_reason: {},
  by_agent: {},

  report_valid: true,
};

const rows = [];

function getNodeItemsSafe(nodeName) {
  try {
    return $items(nodeName).map(item => item.json || {});
  } catch (error) {
    return [];
  }
}

function normalizeResultActionType(result) {
  const raw = firstNonEmpty(
    result.report_action_type,
    result.normalized_action_type,
    result.action_type,
    result.mutation_type
  );

  if (raw === "reassign_pond") return "reassign_to_pond";
  if (raw === "reassign_to_pond") return "reassign_to_pond";
  if (raw === "create_warning_note") return "create_warning_note";
  if (raw === "create_reassignment_note") return "create_reassignment_note";
  if (raw === "note_create") {
    return (
      result.note_type === "reassignment_after_warning" ||
      result.report_group === "reassignment_notes"
    ) ? "create_reassignment_note" : "create_warning_note";
  }

  return raw || null;
}

function executionKey(leadId, actionType) {
  return `${safeTrim(leadId)}__${safeTrim(actionType)}`;
}

const executionResults = [
  ...getNodeItemsSafe('Reassign Report'),
  ...getNodeItemsSafe('Note Report'),
];

const executionResultByKey = new Map();

for (const result of executionResults) {
  const resultActionType = normalizeResultActionType(result);
  const resultLeadId = firstNonEmpty(
    result.lead_id,
    result.id,
    result.personId,
    result.applied_body?.personId,
    result.fub_response_person_id
  );

  if (!resultLeadId || !resultActionType) continue;

  executionResultByKey.set(
    executionKey(resultLeadId, resultActionType),
    result
  );
}

function findExecutionResult(j, actionType) {
  const leadId = firstNonEmpty(j.lead_id, j.id, j.personId, j.body?.personId, j.payload?.personId);
  if (!leadId || !actionType) return null;

  return executionResultByKey.get(executionKey(leadId, actionType)) || null;
}

function classifyExecutionStatus(executionResult, fallbackStatus) {
  if (!executionResult) return fallbackStatus;

  if (executionResult.execution_status) return executionResult.execution_status;

  if (executionResult.execution_success === true) return "SUCCESS";

  if (Number(executionResult.http_status_code) === 429) return "NOTE_FAILED_RATE_LIMIT";

  if (executionResult.execution_success === false) return "FAILED";

  return fallbackStatus;
}


for (const item of items) {
  const j = item.json || {};

  const actionType = normalizeActionType(j);
  const mutationType = normalizeMutationType(j, actionType);
  const reportGroup = getReportGroup(actionType, j);
  const noteType = getNoteType(actionType, j);

  const warningBasedReassignment =
    actionType === "reassign_to_pond" &&
    isWarningBasedReassignment(j);

  const reassignmentRuleType =
    actionType === "reassign_to_pond"
      ? (
          warningBasedReassignment
            ? "warning_based"
            : "standard"
        )
      : null;

  inc(summary.by_router_action, j.router_action);
  inc(summary.by_prepare_execution_status, j.prepare_execution_status);
  inc(summary.by_action_type, actionType);
  inc(summary.by_mutation_type, mutationType);
  inc(summary.by_report_group, reportGroup);

  if (actionType && PROHIBITED_ACTIONS.has(actionType)) {
    summary.prohibited_actions_found += 1;
  }

  if (
    j.router_action === "blocked" ||
    j.execution_status === "blocked" ||
    j.prepare_execution_status === "blocked"
  ) {
    summary.blocked_actions_found += 1;
  }

  if (
    isSkippedOrNoAction(j) ||
    !isPreparedPlannedChange(j, actionType, mutationType)
  ) {
    summary.total_skipped_items += 1;
    continue;
  }

  summary.total_planned_changes += 1;

  if (j.should_execute_fub === true || j.execute_fub_changes === true) {
    summary.should_execute_fub_count += 1;
  }

  if (actionType === "reassign_to_pond") {
    summary.planned_reassign_pond += 1;

    if (warningBasedReassignment) {
      summary.planned_warning_based_reassign_pond += 1;
    } else {
      summary.planned_standard_reassign_pond += 1;
    }
  }

  if (actionType === "create_warning_note") {
    summary.planned_warning_notes += 1;
    summary.planned_note_create += 1;
  }

  if (actionType === "create_reassignment_note") {
    summary.planned_reassignment_notes += 1;
    summary.planned_note_create += 1;
  }

  const reason = getReason(j);
  const agentName = firstNonEmpty(j.agent_name, j.nombre_agente);

  inc(summary.by_reason, reason);
  inc(summary.by_agent, agentName);

  const plannedBody = getPlannedBody(j);
  const executionResult = findExecutionResult(j, actionType);
  const finalExecutionStatus = classifyExecutionStatus(executionResult, j.execution_status);
  const executionSuccess = executionResult?.execution_success;
  const httpStatusCode = executionResult?.http_status_code ?? null;
  const executionErrorMessage = executionResult?.error_message ?? null;

  if (executionResult) {
    inc(summary.by_execution_status, finalExecutionStatus);

    if (executionSuccess === true) {
      summary.execution_success_count += 1;
    } else {
      summary.execution_failed_count += 1;
    }

    if (Number(httpStatusCode) === 429 || finalExecutionStatus === "NOTE_FAILED_RATE_LIMIT") {
      summary.execution_rate_limited_count += 1;
    }
  }

  rows.push({
    item_type: "planned_change_row",

    lead_id: j.lead_id,
    id: j.id ?? j.lead_id,
    name: j.name,
    lead_name: j.lead_name || j.name,
    source: j.source || null,

    agent_id: j.agent_id,
    agent_name: agentName,

    stage_id: j.stage_id || null,
    stage: j.stage || null,

    scenario: j.scenario,
    recommended_action: j.recommended_action,
    reason,
    action_reason: reason,

    transformation_name: getTransformationName(actionType),

    action_type: actionType,
    normalized_action_type: actionType,
    mutation_type: mutationType,

    report_action_type: actionType,
    report_group: reportGroup,
    note_type: noteType,

    method: j.method || j.request_method || null,
    endpoint: j.endpoint || null,
    request_url: j.request_url || null,

    should_execute_fub: j.should_execute_fub === true,
    execute_fub_changes: j.execute_fub_changes === true,

    execution_mode: j.execution_mode,
    execution_status: finalExecutionStatus,
    planned_execution_status: j.execution_status,
    prepare_execution_status: j.prepare_execution_status || null,

    fub_execution_success: executionSuccess === undefined ? null : executionSuccess,
    fub_http_status_code: httpStatusCode,
    fub_error_message: executionErrorMessage,
    fub_response_id: executionResult?.fub_response_id || null,
    fub_retry_after: executionResult?.retry_after || null,

    mutation_prepared: j.mutation_prepared === true,
    mutation_allowed: j.mutation_allowed === true,

    destination_pond_id: j.destination_pond_id || null,
    destination_pond_name: j.destination_pond_name || null,
    reassignment_type: j.reassignment_type || null,

    reassignment_rule_type: reassignmentRuleType,
    reassignment_category: reassignmentRuleType,
    warning_based_reassignment: warningBasedReassignment,
    is_warning_based_reassignment: warningBasedReassignment,
    standard_reassignment:
      actionType === "reassign_to_pond" &&
      !warningBasedReassignment,

    reassignment_after_warning_note:
      j.reassignment_after_warning_note === true ||
      j.action_eligibility?.reassignment_after_warning_note === true,

    should_create_reassignment_note:
      j.should_create_reassignment_note === true ||
      j.action_eligibility?.should_create_reassignment_note === true,

    requires_fresh_tags: j.requires_fresh_tags === true,
    fresh_tags_required: j.fresh_tags_required === true,
    tag_to_add: j.tag_to_add || null,

    planned_body: plannedBody,

    warning_note_subject:
      actionType === "create_warning_note"
        ? firstNonEmpty(
            j.warning_note_subject,
            plannedBody?.subject,
            j.payload?.subject
          )
        : "",

    warning_note_body:
      actionType === "create_warning_note"
        ? firstNonEmpty(
            j.warning_note_body,
            plannedBody?.body,
            plannedBody?.note,
            j.payload?.body,
            j.payload?.note
          )
        : "",

    reassignment_note_subject:
      actionType === "create_reassignment_note"
        ? firstNonEmpty(
            j.reassignment_note_subject,
            plannedBody?.subject,
            j.payload?.subject
          )
        : "",

    reassignment_note_body:
      actionType === "create_reassignment_note"
        ? firstNonEmpty(
            j.reassignment_note_body,
            plannedBody?.body,
            plannedBody?.note,
            j.payload?.body,
            j.payload?.note
          )
        : "",

    fub_lead_url: getLeadUrl(j),

    action_key:
      j.action_key ||
      `${j.lead_id ?? j.id ?? "null"}_${actionType || mutationType}`,

    report_status: executionResult
      ? (executionSuccess === true ? "EXECUTED_SUCCESS" : "EXECUTED_FAILED")
      : "PLANNED_CHANGE",
  });
}

summary.report_valid =
  summary.prohibited_actions_found === 0 &&
  summary.blocked_actions_found === 0;

return [
  { json: summary },
  ...rows.map(row => ({ json: row })),
];

const items = $input.all();

const SOURCE_NODE_NAME = 'Reassign Body';
const TAG_EXPECTED = 'n8n reassignments';
const FUB_LEAD_URL_BASE = 'https://app.followupboss.com/2/people/view';
const DEFAULT_DESTINATION_POND_ID = 272;

function getNodeItems(nodeName) {
  try {
    return $items(nodeName).map(item => item.json);
  } catch (error) {
    return [];
  }
}

function asArray(value) {
  if (!value) return [];
  return Array.isArray(value) ? value : [value];
}

function normalizeId(value) {
  if (value === null || value === undefined || value === '') return null;
  return String(value);
}

function getResponsePayload(json) {
  // Si el HTTP node fue configurado para incluir statusCode/body
  if (json.body && typeof json.body === 'object') {
    return json.body;
  }

  // Si el HTTP node devuelve directamente la respuesta de FUB
  return json || {};
}

function getStatusCode(json) {
  return json.statusCode || json.status || json.response?.statusCode || null;
}

function getErrorMessage(json, responsePayload) {
  if (json.error?.message) return json.error.message;
  if (json.errorMessage) return json.errorMessage;
  if (responsePayload.error?.message) return responsePayload.error.message;
  if (responsePayload.error) return String(responsePayload.error);

  if (
    json.message &&
    String(json.message).toLowerCase().includes('error')
  ) {
    return json.message;
  }

  if (
    responsePayload.message &&
    String(responsePayload.message).toLowerCase().includes('error')
  ) {
    return responsePayload.message;
  }

  return null;
}

const sourceItems = getNodeItems(SOURCE_NODE_NAME);

const resultRows = items.map((item, index) => {
  const currentJson = item.json || {};
  const responsePayload = getResponsePayload(currentJson);

  const responseId = normalizeId(
    responsePayload.id ||
    responsePayload.personId ||
    currentJson.id ||
    currentJson.lead_id
  );

  let source = sourceItems[index] || {};

  if (responseId) {
    const matchById = sourceItems.find(sourceItem => {
      return (
        normalizeId(sourceItem.lead_id) === responseId ||
        normalizeId(sourceItem.id) === responseId ||
        normalizeId(sourceItem.personId) === responseId
      );
    });

    if (matchById) {
      source = matchById;
    }
  }

  const appliedBody = source.body || currentJson.body || {};

  const leadId =
    source.lead_id ||
    source.id ||
    responsePayload.id ||
    currentJson.lead_id ||
    currentJson.id ||
    null;

  const destinationPondId =
    appliedBody.assignedPondId ||
    source.destination_pond_id ||
    source.destinationPondId ||
    responsePayload.assignedPondId ||
    DEFAULT_DESTINATION_POND_ID;

  const responseAssignedPondId =
    responsePayload.assignedPondId ||
    responsePayload.assigned_pond_id ||
    null;

  const appliedTags = asArray(appliedBody.tags);
  const responseTags = asArray(responsePayload.tags);

  const statusCode = getStatusCode(currentJson);
  const errorMessage = getErrorMessage(currentJson, responsePayload);

  const hasSuccessfulStatus =
    !statusCode || (Number(statusCode) >= 200 && Number(statusCode) < 300);

  const pondMatches =
    responseAssignedPondId === null ||
    Number(responseAssignedPondId) === Number(destinationPondId);

  const executionSuccess =
    !errorMessage &&
    hasSuccessfulStatus &&
    pondMatches;

  const warnings = [];

  if (!leadId) {
    warnings.push('lead_id_not_found');
  }

  if (!appliedBody.assignedPondId) {
    warnings.push('assignedPondId_not_found_in_applied_body');
  }

  if (!appliedTags.includes(TAG_EXPECTED)) {
    warnings.push('expected_tag_not_found_in_applied_body');
  }

  if (responseAssignedPondId !== null && !pondMatches) {
    warnings.push('response_pond_does_not_match_destination_pond');
  }

  return {
    json: {
      row_type: 'execution_result_row',
      report_section: 'reassign_result',

      executed_at: new Date().toISOString(),

      action_type: 'reassign_pond',
      mutation_type: 'reassign_pond',

      lead_id: leadId,
      lead_name:
        source.lead_name ||
        source.name ||
        responsePayload.name ||
        null,

      agent_id:
        source.agent_id ||
        source.assignedUserId ||
        null,

      agent_name:
        source.agent_name ||
        source.agent ||
        null,

      request_method: 'PUT',
      request_url:
        source.request_url ||
        currentJson.request_url ||
        null,

      reason: source.reason || null,
      destination_pond_id: destinationPondId,
      destination_pond_name: source.destination_pond_name || null,
      new_pond_id: destinationPondId,
      link_fub_lead: leadId ? `${FUB_LEAD_URL_BASE}/${leadId}` : null,
      fub_response_assigned_pond_id: responseAssignedPondId,

      tag_expected: TAG_EXPECTED,
      tag_present_in_applied_body: appliedTags.includes(TAG_EXPECTED),
      tag_present_in_fub_response: responseTags.includes(TAG_EXPECTED),

      applied_body: appliedBody,

      fub_response_id: responsePayload.id || null,
      fub_response_snapshot: {
        id: responsePayload.id || null,
        name: responsePayload.name || null,
        assignedPondId: responsePayload.assignedPondId || null,
        stageId: responsePayload.stageId || null,
        tags: responseTags,
      },

      http_status_code: statusCode,

      execution_success: executionSuccess,
      execution_status: executionSuccess ? 'SUCCESS' : 'FAILED',
      error_message: executionSuccess
        ? null
        : errorMessage || 'Reassign response could not be fully validated',

      warnings,

      prohibited_action_found: false,
      stage_change_attempted: false,
      task_create_attempted: false,
    }
  };
});

return resultRows;

/****************************************************************************************
 * NODE: Note Report
 * MODE: Run Once for All Items
 *
 * Purpose:
 * - Report actual FUB Create Note execution result.
 * - Preserve create_warning_note vs create_reassignment_note.
 * - Classify 429/rate-limit failures clearly.
 * - Do not validate all notes against subject "n8n warning" only.
 ****************************************************************************************/

const items = $input.all();

const SOURCE_NODE_CANDIDATES = [
  'Note Rate Limit Wait',
  'Loop Over Items1',
  'Prepare FUB Mutations',
];

const FUB_LEAD_URL_BASE = 'https://app.followupboss.com/2/people/view';

function getNodeItems(nodeName) {
  try {
    return $items(nodeName).map(item => item.json || {});
  } catch (error) {
    return [];
  }
}

function normalizeId(value) {
  if (value === null || value === undefined || value === '') return null;
  return String(value);
}

function safeString(value, fallback = '') {
  if (value === undefined || value === null) return String(fallback);
  return String(value);
}

function safeTrim(value, fallback = '') {
  return safeString(value, fallback).trim();
}

function firstNonEmpty(...values) {
  for (const value of values) {
    const clean = safeTrim(value);
    if (clean !== '') return clean;
  }
  return '';
}

function getResponsePayload(json) {
  if (json.body && typeof json.body === 'object') {
    return json.body;
  }
  return json || {};
}

function getStatusCode(json) {
  return (
    json.statusCode ||
    json.status ||
    json.response?.statusCode ||
    json.response?.status ||
    null
  );
}

function getRetryAfter(json) {
  return (
    json.headers?.['retry-after'] ||
    json.headers?.['Retry-After'] ||
    json.response?.headers?.['retry-after'] ||
    null
  );
}

function getErrorMessage(json, responsePayload) {
  if (json.error?.message) return json.error.message;
  if (json.errorMessage) return json.errorMessage;

  if (responsePayload.errorMessage) return responsePayload.errorMessage;
  if (responsePayload.error?.message) return responsePayload.error.message;
  if (responsePayload.error) return String(responsePayload.error);

  if (json.message) return String(json.message);
  if (responsePayload.message) return String(responsePayload.message);

  return null;
}

function getPairedIndex(item) {
  const paired = item.pairedItem;

  if (paired === undefined || paired === null) return null;

  if (Array.isArray(paired)) {
    const first = paired[0];
    if (first && Number.isFinite(Number(first.item))) return Number(first.item);
    return null;
  }

  if (Number.isFinite(Number(paired.item))) return Number(paired.item);

  return null;
}

function normalizeActionType(source, responsePayload) {
  const raw = firstNonEmpty(
    source.report_action_type,
    source.normalized_action_type,
    source.action_type,
    source.mutation_type
  );

  if (raw === 'create_reassignment_note') return 'create_reassignment_note';
  if (raw === 'create_warning_note') return 'create_warning_note';
  if (raw === 'note_create') {
    return (
      source.note_type === 'reassignment_after_warning' ||
      source.report_group === 'reassignment_notes' ||
      source.reassignment_type === 'reassignment_after_warning'
    ) ? 'create_reassignment_note' : 'create_warning_note';
  }

  if (safeTrim(responsePayload.subject).toLowerCase() === 'n8n reassignment') {
    return 'create_reassignment_note';
  }

  return raw || 'create_warning_note';
}

function noteTypeForAction(actionType, source) {
  if (source.note_type) return source.note_type;
  if (actionType === 'create_reassignment_note') return 'reassignment_after_warning';
  return 'warning_note';
}

function findSourceData(item, currentJson, responsePayload, index, sourceItems) {
  const pairedIndex = getPairedIndex(item);
  if (pairedIndex !== null && sourceItems[pairedIndex]) {
    return sourceItems[pairedIndex];
  }

  const responsePersonId = normalizeId(
    responsePayload.personId ||
    responsePayload.person_id ||
    responsePayload.person?.id ||
    currentJson.personId ||
    currentJson.lead_id ||
    currentJson.id
  );

  if (
    currentJson.lead_id ||
    currentJson.request_url ||
    currentJson.mutation_type === 'note_create'
  ) {
    return currentJson;
  }

  if (responsePersonId) {
    const found = sourceItems.find(sourceItem => {
      return (
        normalizeId(sourceItem.lead_id) === responsePersonId ||
        normalizeId(sourceItem.id) === responsePersonId ||
        normalizeId(sourceItem.personId) === responsePersonId ||
        normalizeId(sourceItem.body?.personId) === responsePersonId ||
        normalizeId(sourceItem.payload?.personId) === responsePersonId
      );
    });

    if (found) return found;
  }

  return sourceItems[index] || {};
}

const sourceItems = SOURCE_NODE_CANDIDATES.flatMap(getNodeItems);

const resultRows = items.map((item, index) => {
  const currentJson = item.json || {};
  const responsePayload = getResponsePayload(currentJson);
  const source = findSourceData(item, currentJson, responsePayload, index, sourceItems);

  const appliedBody = source.body || currentJson.body || source.payload || {};
  const actionType = normalizeActionType(source, responsePayload);
  const noteType = noteTypeForAction(actionType, source);

  const leadId =
    source.lead_id ||
    source.id ||
    source.personId ||
    appliedBody.personId ||
    responsePayload.personId ||
    responsePayload.person_id ||
    responsePayload.person?.id ||
    null;

  const noteId =
    responsePayload.id ||
    responsePayload.noteId ||
    responsePayload.note_id ||
    null;

  const statusCode = getStatusCode(currentJson);
  const errorMessage = getErrorMessage(currentJson, responsePayload);
  const retryAfter = getRetryAfter(currentJson);

  const hasSuccessfulStatus =
    !statusCode || (Number(statusCode) >= 200 && Number(statusCode) < 300);

  const responsePersonId =
    responsePayload.personId ||
    responsePayload.person_id ||
    responsePayload.person?.id ||
    null;

  const personMatches =
    !responsePersonId ||
    !leadId ||
    normalizeId(responsePersonId) === normalizeId(leadId);

  const isRateLimited =
    Number(statusCode) === 429 ||
    safeString(errorMessage).toLowerCase().includes('rate limit') ||
    safeString(errorMessage).toLowerCase().includes('too many requests');

  const executionSuccess =
    !errorMessage &&
    hasSuccessfulStatus &&
    personMatches &&
    Boolean(noteId || responsePayload.created || responsePayload.createdAt);

  let executionStatus = 'NOTE_FAILED_VALIDATION';

  if (executionSuccess) {
    executionStatus = 'NOTE_CREATED';
  } else if (isRateLimited) {
    executionStatus = 'NOTE_FAILED_RATE_LIMIT';
  } else if (statusCode && Number(statusCode) >= 400) {
    executionStatus = 'NOTE_FAILED_API_ERROR';
  }

  const warnings = [];

  if (!leadId) warnings.push('lead_id_not_found');
  if (!noteId && executionSuccess) warnings.push('note_id_not_found_in_response');
  if (!appliedBody.personId) warnings.push('personId_not_found_in_applied_body');
  if (!appliedBody.subject) warnings.push('subject_not_found_in_applied_body');
  if (responsePersonId && leadId && !personMatches) warnings.push('response_personId_does_not_match_lead_id');
  if (isRateLimited) warnings.push(`rate_limited_retry_after:${retryAfter || 'unknown'}`);

  return {
    json: {
      row_type: 'execution_result_row',
      report_section: 'note_result',
      executed_at: new Date().toISOString(),

      action_type: actionType,
      normalized_action_type: actionType,
      report_action_type: actionType,
      report_group: actionType === 'create_reassignment_note' ? 'reassignment_notes' : 'warning_notes',
      mutation_type: 'note_create',
      note_type: noteType,

      lead_id: leadId,
      lead_name:
        source.lead_name ||
        source.name ||
        responsePayload.person?.name ||
        null,

      agent_id:
        source.agent_id ||
        source.assignedUserId ||
        null,

      agent_name:
        source.agent_name ||
        source.agent ||
        null,

      request_method: 'POST',
      request_url:
        source.request_url ||
        currentJson.request_url ||
        'https://api.followupboss.com/v1/notes',

      reason: source.action_reason || source.reason || source.action_eligibility?.action_reason || null,
      link_fub_lead: leadId ? `${FUB_LEAD_URL_BASE}/${leadId}` : null,

      note_subject: appliedBody.subject || responsePayload.subject || null,
      note_body: appliedBody.body || appliedBody.note || responsePayload.body || null,
      note_is_html: appliedBody.isHtml ?? null,

      warning_note_subject: actionType === 'create_warning_note' ? (appliedBody.subject || responsePayload.subject || null) : null,
      warning_note_body: actionType === 'create_warning_note' ? (appliedBody.body || appliedBody.note || responsePayload.body || null) : null,
      reassignment_note_subject: actionType === 'create_reassignment_note' ? (appliedBody.subject || responsePayload.subject || null) : null,
      reassignment_note_body: actionType === 'create_reassignment_note' ? (appliedBody.body || appliedBody.note || responsePayload.body || null) : null,

      applied_body: appliedBody,

      fub_response_id: noteId,
      fub_response_person_id: responsePersonId,
      fub_response_snapshot: {
        id: noteId,
        personId: responsePersonId,
        subject: responsePayload.subject || null,
        body: responsePayload.body || null,
        created: responsePayload.created || responsePayload.createdAt || null,
      },

      http_status_code: statusCode,
      retry_after: retryAfter,

      execution_success: executionSuccess,
      execution_status: executionStatus,
      error_message: executionSuccess
        ? null
        : errorMessage || 'Note creation response could not be fully validated',

      warnings,

      prohibited_action_found: false,
      stage_change_attempted: false,
      task_create_attempted: false,
      reassign_attempted: false,
    }
  };
});

return resultRows;

/****************************************************************************************
 * NODE: Build Final Audit Report
 * MODE: Run Once for All Items
 *
 * OBJECTIVE:
 * - Build the structured final audit report consumed by Build Email Report.
 * - Keep existing working logic intact.
 * - Split pond reassignments into:
 *   1) Standard Pond Reassignments
 *      Normal audit-rule reassignments, excluding warning-based escalation.
 *   2) Warning-Based Pond Reassignments
 *      Leads reassigned because they already had an automation warning note
 *      and no action was taken.
 * - Keep first warning notes separated.
 * - Preserve reassignment-note rows for compatibility and totals.
 *
 * OUTPUT:
 * 1) final_report_summary
 * 2) final_report_markdown
 * 3) final_standard_reassign_table rows
 * 4) final_warning_based_reassign_table rows
 * 5) final_reassignment_note_table rows
 * 6) final_note_table rows
 ****************************************************************************************/

const items = $input.all().map(item => item.json || {});

const FUB_LEAD_URL_BASE = 'https://app.followupboss.com/2/people/view';

function safeString(value, fallback = '') {
  if (value === undefined || value === null) return String(fallback);
  return String(value);
}

function safeTrim(value, fallback = '') {
  return safeString(value, fallback).trim();
}

function firstNonEmpty(...values) {
  for (const value of values) {
    const clean = safeTrim(value);
    if (clean !== '') return clean;
  }
  return '';
}

function toNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function cleanMarkdown(value) {
  return safeString(value)
    .replace(/\|/g, '\\|')
    .replace(/\r\n/g, ' ')
    .replace(/\n/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function fubLink(leadId) {
  const cleanLeadId = safeTrim(leadId);
  return cleanLeadId ? `${FUB_LEAD_URL_BASE}/${cleanLeadId}` : '';
}

function getSummarySource() {
  return (
    items.find(row => row.item_type === 'planned_changes_summary') ||
    items.find(row => row.row_type === 'planned_changes_summary') ||
    items.find(row => row.report_section === 'planned_changes_summary') ||
    items.find(row => row.row_type === 'final_report_summary') ||
    items.find(row => row.report_section === 'final_summary') ||
    items.find(row => row.item_type === 'summary') ||
    {}
  );
}

function getActionType(row) {
  return safeTrim(
    row.report_action_type ||
    row.normalized_action_type ||
    row.action_type ||
    row.mutation_type ||
    row.action_bucket ||
    row.recommended_action ||
    ''
  );
}

function isExecutableOrPrepared(row) {
  if (row.mutation_prepared === true) return true;
  if (row.mutation_allowed === true) return true;
  if (row.prepare_execution_status === 'ready_to_execute') return true;
  if (row.prepare_execution_status === 'prepared_not_executing') return true;
  if (row.execution_status === 'ready_to_execute') return true;
  if (row.execution_status === 'prepared_not_executing') return true;
  if (row.execution_status === 'dry_run_ready') return true;
  if (row.execution_status === 'prepared_report_only') return true;
  if (row.row_type === 'planned_change_row') return true;
  if (row.item_type === 'planned_change_row') return true;
  if (row.report_section === 'planned_changes') return true;
  if (row.report_section === 'final_standard_reassign_table') return true;
  if (row.report_section === 'final_warning_based_reassign_table') return true;
  if (row.report_section === 'final_reassign_table') return true;
  if (row.report_section === 'final_note_table') return true;
  if (row.report_section === 'final_reassignment_note_table') return true;
  return false;
}

function isSkippedOrNoAction(row) {
  return (
    row.should_skip === true ||
    row.recommended_action === 'NO_ACTION' ||
    row.action_bucket === 'NO_ACTION' ||
    row.router_action === 'skip' ||
    row.router_action === 'blocked' ||
    row.execution_status === 'skipped' ||
    row.execution_status === 'blocked' ||
    row.prepare_execution_status === 'skipped' ||
    row.prepare_execution_status === 'blocked'
  );
}

function rowText(row) {
  return [
    row.reason,
    row.action_reason,
    row.reassignment_reason,
    row.warning_reason,
    row.reassignment_note_reason,
    row.razon_reasignacion,
    row.razon_nota,
    row.razon_nota_reasignacion,
    row.action_key,
  ].map(value => safeString(value).toLowerCase()).join(' | ');
}

function isReassignmentNoteRow(row) {
  const actionType = getActionType(row);
  const noteType = safeTrim(row.note_type);
  const reportGroup = safeTrim(row.report_group);
  const actionKey = safeTrim(row.action_key);

  return (
    row.report_section === 'final_reassignment_note_table' ||
    noteType === 'reassignment_after_warning' ||
    reportGroup === 'reassignment_notes' ||
    actionType === 'create_reassignment_note' ||
    row.action_type === 'create_reassignment_note' ||
    row.normalized_action_type === 'create_reassignment_note' ||
    row.report_action_type === 'create_reassignment_note' ||
    actionKey.includes('reassign_after_warning_note')
  );
}

function isWarningNoteRow(row) {
  if (isReassignmentNoteRow(row)) return false;

  const actionType = getActionType(row);
  const noteType = safeTrim(row.note_type);
  const reportGroup = safeTrim(row.report_group);

  return (
    row.report_section === 'final_note_table' ||
    noteType === 'warning_note' ||
    reportGroup === 'warning_notes' ||
    actionType === 'create_warning_note' ||
    actionType === 'WARNING_NOTE' ||
    row.normalized_action_type === 'create_warning_note' ||
    row.action_type === 'create_warning_note' ||
    row.report_action_type === 'create_warning_note' ||
    row.action_group === 'note' ||
    row.should_create_warning_note === true ||
    (
      row.mutation_type === 'note_create' &&
      !isReassignmentNoteRow(row)
    )
  );
}

function isReassignRow(row) {
  if (isWarningNoteRow(row) || isReassignmentNoteRow(row)) return false;

  const actionType = getActionType(row);
  const reportGroup = safeTrim(row.report_group);

  return (
    row.report_section === 'final_standard_reassign_table' ||
    row.report_section === 'final_warning_based_reassign_table' ||
    row.report_section === 'final_reassign_table' ||
    reportGroup === 'pond_reassignments' ||
    actionType === 'reassign_pond' ||
    actionType === 'reassign_to_pond' ||
    actionType === 'REASSIGN' ||
    actionType === 'REASSIGN_POND' ||
    row.mutation_type === 'reassign_pond' ||
    row.normalized_action_type === 'reassign_to_pond' ||
    row.action_type === 'reassign_to_pond' ||
    row.report_action_type === 'reassign_to_pond' ||
    row.action_group === 'reassign' ||
    (
      row.should_reassign === true &&
      row.mutation_type !== 'note_create'
    )
  );
}

function isWarningBasedReassignRow(row) {
  if (!isReassignRow(row)) return false;

  const text = rowText(row);

  return (
    row.report_section === 'final_warning_based_reassign_table' ||
    row.reassignment_rule_type === 'warning_based' ||
    row.reassignment_category === 'warning_based' ||
    row.warning_based_reassignment === true ||
    row.is_warning_based_reassignment === true ||
    row.reassignment_after_warning_note === true ||
    row.should_create_reassignment_note === true ||
    row.action_eligibility?.reassignment_after_warning_note === true ||
    row.action_eligibility?.should_create_reassignment_note === true ||
    (
      text.includes('automation warning note') &&
      (
        text.includes('duplicate warning') ||
        text.includes('already has') ||
        text.includes('already had') ||
        text.includes('no action')
      )
    )
  );
}

function normalizeLeadId(row) {
  return firstNonEmpty(
    row.lead_id,
    row.id,
    row.personId,
    row.person_id,
    row.body?.personId,
    row.payload?.personId,
    row.lead_info?.lead_id,
    row.lead_info?.id
  );
}

function normalizeLeadName(row) {
  return firstNonEmpty(
    row.lead_name,
    row.name,
    row.nombre_lead,
    row.lead_info?.name
  );
}

function normalizeAgentId(row) {
  return firstNonEmpty(
    row.agent_id,
    row.agente_id,
    row.lead_info?.agent_id
  );
}

function normalizeAgentName(row) {
  return firstNonEmpty(
    row.agent_name,
    row.nombre_agente,
    row.lead_info?.agent_name
  );
}

function normalizeReason(row) {
  return firstNonEmpty(
    row.action_reason,
    row.reason,
    row.reassignment_reason,
    row.warning_reason,
    row.reassignment_note_reason,
    row.razon_reasignacion,
    row.razon_nota,
    row.razon_nota_reasignacion,
    row.action_eligibility?.action_reason
  );
}

function normalizeExecutionStatus(row) {
  return firstNonEmpty(
    row.execution_status,
    row.prepare_execution_status,
    row.status
  );
}

function normalizeDestinationPondId(row) {
  return firstNonEmpty(
    row.destination_pond_id,
    row.pond_nuevo_id,
    row.new_pond_id,
    row.body?.assignedPondId,
    row.payload?.assignedPondId,
    272
  );
}

function normalizeDestinationPondName(row) {
  return firstNonEmpty(
    row.destination_pond_name,
    row.pond_nuevo_nombre,
    row.new_pond_name,
    'Buyer Reassignment Pond'
  );
}

function normalizeFubLeadLink(row) {
  const leadId = normalizeLeadId(row);

  return firstNonEmpty(
    row.fub_lead_url,
    row.link_fub_lead,
    leadId ? fubLink(leadId) : ''
  );
}

function normalizeNoteSubject(row) {
  return firstNonEmpty(
    row.reassignment_note_subject,
    row.warning_note_subject,
    row.payload?.subject,
    row.planned_body?.subject,
    row.body?.subject,
    row.note_subject,
    ''
  );
}

function normalizeNoteBody(row) {
  return firstNonEmpty(
    row.reassignment_note_body,
    row.warning_note_body,
    row.payload?.body,
    row.payload?.note,
    row.planned_body?.body,
    row.planned_body?.note,
    row.body?.body,
    row.body?.note,
    row.note_body,
    ''
  );
}

function normalizePondLabel(row) {
  const pondId = normalizeDestinationPondId(row);
  const pondName = normalizeDestinationPondName(row);
  return `${pondId} - ${pondName}`;
}

let candidateRows = items.filter(row =>
  isExecutableOrPrepared(row) &&
  !isSkippedOrNoAction(row) &&
  (
    isReassignRow(row) ||
    isWarningNoteRow(row) ||
    isReassignmentNoteRow(row)
  )
);

if (candidateRows.length === 0) {
  candidateRows = items.filter(row =>
    (
      row.report_section === 'final_standard_reassign_table' ||
      row.report_section === 'final_warning_based_reassign_table' ||
      row.report_section === 'final_reassign_table' ||
      row.report_section === 'final_note_table' ||
      row.report_section === 'final_reassignment_note_table'
    ) &&
    !isSkippedOrNoAction(row)
  );
}

const rawReassignRows = candidateRows.filter(isReassignRow);
const rawReassignmentNoteRows = candidateRows.filter(isReassignmentNoteRow);
const rawWarningNoteRows = candidateRows.filter(isWarningNoteRow);

const reassignmentNoteByLeadId = new Map();

for (const row of rawReassignmentNoteRows) {
  const leadId = normalizeLeadId(row);
  if (!leadId || reassignmentNoteByLeadId.has(String(leadId))) continue;
  reassignmentNoteByLeadId.set(String(leadId), row);
}

function buildReassignRow(row, section, actionGroup, reassignmentRuleType) {
  const leadId = normalizeLeadId(row);
  const leadName = normalizeLeadName(row);
  const agentId = normalizeAgentId(row);
  const agentName = normalizeAgentName(row);
  const reason = normalizeReason(row);
  const leadUrl = normalizeFubLeadLink(row);
  const destinationPondId = normalizeDestinationPondId(row);
  const destinationPondName = normalizeDestinationPondName(row);
  const noteRow = reassignmentNoteByLeadId.get(String(leadId)) || {};

  const noteSubject = normalizeNoteSubject(noteRow);
  const noteBody = normalizeNoteBody(noteRow);

  return {
    row_type: 'final_report_detail',
    item_type: 'final_report_detail',
    report_section: section,
    action_group: actionGroup,

    id: leadId,
    lead_id: leadId,
    lead_name: leadName,

    agent_id: agentId,
    agent_name: agentName,

    reassignment_reason: reason,

    destination_pond_id: destinationPondId,
    destination_pond_name: destinationPondName,
    destination_pond_label: `${destinationPondId} - ${destinationPondName}`,

    fub_lead_url: leadUrl,
    execution_status: normalizeExecutionStatus(row),

    report_action_type: 'reassign_to_pond',
    report_group: 'pond_reassignments',
    note_type: null,

    reassignment_rule_type: reassignmentRuleType,
    reassignment_category: reassignmentRuleType,
    warning_based_reassignment: reassignmentRuleType === 'warning_based',
    standard_reassignment: reassignmentRuleType === 'standard',

    reassignment_note_subject: noteSubject,
    reassignment_note_body: noteBody,
    has_reassignment_note: Boolean(noteSubject || noteBody),

    nombre_lead: leadName,
    agente_id: agentId,
    nombre_agente: agentName,
    razon_reasignacion: reason,
    pond_nuevo_id: destinationPondId,
    pond_nuevo_nombre: destinationPondName,
    link_fub_lead: leadUrl,
  };
}

const standardReassignRows = rawReassignRows
  .filter(row => !isWarningBasedReassignRow(row))
  .map(row => buildReassignRow(
    row,
    'final_standard_reassign_table',
    'standard_reassign',
    'standard'
  ));

const warningBasedReassignRows = rawReassignRows
  .filter(isWarningBasedReassignRow)
  .map(row => buildReassignRow(
    row,
    'final_warning_based_reassign_table',
    'warning_based_reassign',
    'warning_based'
  ));

const reassignmentNoteRows = rawReassignmentNoteRows
  .map(row => {
    const leadId = normalizeLeadId(row);
    const leadName = normalizeLeadName(row);
    const agentId = normalizeAgentId(row);
    const agentName = normalizeAgentName(row);
    const reason = normalizeReason(row);
    const leadUrl = normalizeFubLeadLink(row);
    const noteSubject = normalizeNoteSubject(row);
    const noteBody = normalizeNoteBody(row);

    return {
      row_type: 'final_report_detail',
      item_type: 'final_report_detail',
      report_section: 'final_reassignment_note_table',
      action_group: 'reassignment_note',

      id: leadId,
      lead_id: leadId,
      lead_name: leadName,

      agent_id: agentId,
      agent_name: agentName,

      reassignment_note_reason: reason,
      reassignment_note_subject: noteSubject,
      reassignment_note_body: noteBody,

      fub_lead_url: leadUrl,
      execution_status: normalizeExecutionStatus(row),

      report_action_type: 'create_reassignment_note',
      report_group: 'reassignment_notes',
      note_type: 'reassignment_after_warning',

      nombre_lead: leadName,
      agente_id: agentId,
      nombre_agente: agentName,
      razon_nota_reasignacion: reason,
      asunto_nota_reasignacion: noteSubject,
      cuerpo_nota_reasignacion: noteBody,
      link_fub_lead: leadUrl,
    };
  });

const noteRows = rawWarningNoteRows
  .map(row => {
    const leadId = normalizeLeadId(row);
    const leadName = normalizeLeadName(row);
    const agentId = normalizeAgentId(row);
    const agentName = normalizeAgentName(row);
    const reason = normalizeReason(row);
    const leadUrl = normalizeFubLeadLink(row);
    const noteSubject = normalizeNoteSubject(row);

    return {
      row_type: 'final_report_detail',
      item_type: 'final_report_detail',
      report_section: 'final_note_table',
      action_group: 'note',

      id: leadId,
      lead_id: leadId,
      lead_name: leadName,

      agent_id: agentId,
      agent_name: agentName,

      warning_reason: reason,
      warning_note_subject: noteSubject,

      fub_lead_url: leadUrl,
      execution_status: normalizeExecutionStatus(row),

      report_action_type: 'create_warning_note',
      report_group: 'warning_notes',
      note_type: 'warning_note',

      nombre_lead: leadName,
      agente_id: agentId,
      nombre_agente: agentName,
      razon_nota: reason,
      asunto_nota_warning: noteSubject,
      link_fub_lead: leadUrl,
    };
  });

function sortRows(a, b) {
  return (
    safeString(a.agent_name).localeCompare(safeString(b.agent_name)) ||
    safeString(a.lead_name).localeCompare(safeString(b.lead_name)) ||
    safeString(a.lead_id).localeCompare(safeString(b.lead_id))
  );
}

standardReassignRows.sort(sortRows);
warningBasedReassignRows.sort(sortRows);
reassignmentNoteRows.sort(sortRows);
noteRows.sort(sortRows);

const summarySource = getSummarySource();

const totalReviewed = toNumber(
  firstNonEmpty(
    summarySource.total_leads_reviewed,
    summarySource.total_router_items,
    summarySource.total_audited,
    summarySource.total_items,
    summarySource.numero_total_registros_auditados
  ),
  items.length
);

const totalStandardReassignments = standardReassignRows.length;
const totalWarningBasedReassignments = warningBasedReassignRows.length;
const totalReassignments = totalStandardReassignments + totalWarningBasedReassignments;
const totalWarningNotes = noteRows.length;
const totalReassignmentNotes = reassignmentNoteRows.length;
const totalNotes = totalWarningNotes + totalReassignmentNotes;
const totalPlannedChanges =
  totalReassignments +
  totalWarningNotes +
  totalReassignmentNotes;

function buildStandardReassignMarkdown(rows) {
  return rows.length
    ? rows.map(row =>
        `| ${cleanMarkdown(row.lead_id)} | ${cleanMarkdown(row.lead_name)} | ${cleanMarkdown(row.agent_name)} | ${cleanMarkdown(row.reassignment_reason)} | ${cleanMarkdown(row.destination_pond_label)} | ${cleanMarkdown(row.fub_lead_url)} |`
      ).join('\n')
    : '| - | - | - | - | - | - |';
