];

/****************************************************************************************
 * NODE: Build Email Report
 * MODE: Run Once for All Items
 *
 * OBJECTIVE:
 * - Receive rows from Build Final Audit Report.
 * - Build ONE final email payload for Gmail.
 * - Report in English.
 * - Show the audit in a clearer structure:
 *   1) Standard Pond Reassignments
 *      Normal audit-rule reassignments, excluding warning-based escalation.
 *   2) Warning-Based Pond Reassignments
 *      Leads reassigned because they already had an automation warning note
 *      and no action was taken. Reassignment-note details are shown here.
 *   3) First Warning Notes
 *
 * IMPORTANT:
 * - Reassignment notes are still counted as planned FUB mutations.
 * - Reassignment notes are not shown as a separate decision table anymore;
 *   they are attached to the matching warning-based reassignment row.
 * - Always return safe string fields to prevent Gmail .trim() errors.
 ****************************************************************************************/

const items = $input.all().map(item => item.json || {});

const REPORT_TITLE = 'Buyer Lead Reassignment Audit Report';

const EMAIL_TO = 'demo@example.com';
const EMAIL_CC = '';
const EMAIL_BCC = '';

const SLACK_MANAGER_CHANNEL = 'CXXXXXXXXXX';
const SLACK_TEAM_CHANNEL = 'CYYYYYYYYYY';

function safeString(value, fallback = '') {
  if (value === undefined || value === null) return String(fallback);
  return String(value);
}

function safeTrim(value, fallback = '') {
  return safeString(value, fallback).trim();
}

function firstNonEmpty(...values) {
  for (const value of values) {
    const clean = safeTrim(value);
    if (clean !== '') return clean;
  }
  return '';
}

function toNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function escapeHtml(value) {
  return safeString(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function escapeAttr(value) {
  return escapeHtml(value);
}

function cleanCell(value) {
  return safeString(value)
    .replace(/\r\n/g, ' ')
    .replace(/\n/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function cleanPlainText(value) {
  return safeString(value)
    .replace(/\r\n/g, '\n')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function formatGeneratedAt(value) {
  const date = value ? new Date(value) : new Date();

  if (Number.isNaN(date.getTime())) {
    return new Date().toISOString();
  }

  return date.toLocaleString('en-US', {
    timeZone: 'America/Los_Angeles',
    year: 'numeric',
    month: 'short',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
  });
}

function formatSubjectDate(value) {
  const date = value ? new Date(value) : new Date();

  if (Number.isNaN(date.getTime())) {
    return new Date().toISOString().slice(0, 10);
  }

  return date.toLocaleDateString('en-CA', {
    timeZone: 'America/Los_Angeles',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  });
}

function getSummaryRow() {
  return (
    items.find(row => row.report_section === 'final_summary') ||
    items.find(row => row.row_type === 'final_report_summary') ||
    items.find(row => row.item_type === 'final_report_summary') ||
    {}
  );
}

function getMarkdownRow() {
  return (
    items.find(row => row.report_section === 'final_markdown') ||
    items.find(row => row.row_type === 'final_report_markdown') ||
    items.find(row => row.item_type === 'final_report_markdown') ||
    {}
  );
}

function getRowsBySection(section) {
  return items.filter(row => row.report_section === section);
}

function rowText(row) {
  return [
    row.reason,
    row.action_reason,
    row.reassignment_reason,
    row.warning_reason,
    row.reassignment_note_reason,
    row.razon_reasignacion,
    row.razon_nota,
    row.razon_nota_reasignacion,
    row.action_key,
  ].map(value => safeString(value).toLowerCase()).join(' | ');
}

function isReassignmentNote(row) {
  const actionKey = safeTrim(row.action_key);

  return (
    row.report_section === 'final_reassignment_note_table' ||
    row.report_group === 'reassignment_notes' ||
    row.report_action_type === 'create_reassignment_note' ||
    row.note_type === 'reassignment_after_warning' ||
    row.action_group === 'reassignment_note' ||
    row.action_type === 'create_reassignment_note' ||
    row.normalized_action_type === 'create_reassignment_note' ||
    actionKey.includes('reassign_after_warning_note')
  );
}

function isReassign(row) {
  if (isReassignmentNote(row)) return false;

  return (
    row.report_section === 'final_standard_reassign_table' ||
    row.report_section === 'final_warning_based_reassign_table' ||
    row.report_section === 'final_reassign_table' ||
    row.report_group === 'pond_reassignments' ||
    row.report_action_type === 'reassign_to_pond' ||
    row.action_group === 'reassign' ||
    row.action_group === 'standard_reassign' ||
    row.action_group === 'warning_based_reassign' ||
    row.mutation_type === 'reassign_pond' ||
    row.action_type === 'reassign_to_pond' ||
    row.normalized_action_type === 'reassign_to_pond'
  );
}

function isWarningBasedReassign(row) {
  if (!isReassign(row)) return false;

  const text = rowText(row);

  return (
    row.report_section === 'final_warning_based_reassign_table' ||
    row.reassignment_rule_type === 'warning_based' ||
    row.reassignment_category === 'warning_based' ||
    row.warning_based_reassignment === true ||
    row.is_warning_based_reassignment === true ||
    row.reassignment_after_warning_note === true ||
    row.should_create_reassignment_note === true ||
    (
      text.includes('automation warning note') &&
      (
        text.includes('duplicate warning') ||
        text.includes('already has') ||
        text.includes('already had') ||
        text.includes('no action')
      )
    )
  );
}

function isStandardReassign(row) {
  if (!isReassign(row)) return false;
  if (row.report_section === 'final_standard_reassign_table') return true;
  return !isWarningBasedReassign(row);
}

function isWarningNote(row) {
  if (isReassignmentNote(row)) return false;

  return (
    row.report_section === 'final_note_table' ||
    row.report_group === 'warning_notes' ||
    row.report_action_type === 'create_warning_note' ||
    row.note_type === 'warning_note' ||
    row.action_group === 'note' ||
    row.action_type === 'create_warning_note' ||
    row.normalized_action_type === 'create_warning_note' ||
    (
      row.mutation_type === 'note_create' &&
      row.note_type !== 'reassignment_after_warning'
    )
  );
}

function dedupeRows(rows) {
  const seen = new Set();
  const output = [];

  for (const row of rows) {
    const key = [
      firstNonEmpty(row.report_section, row.report_group, row.action_group),
      firstNonEmpty(row.action_key, ''),
      firstNonEmpty(row.lead_id, row.id, row.personId),
      firstNonEmpty(row.report_action_type, row.action_type, row.mutation_type),
      firstNonEmpty(row.note_type, ''),
    ].join('|');

    if (seen.has(key)) continue;
    seen.add(key);
    output.push(row);
  }

  return output;
}

function sortRows(a, b) {
  return (
    safeString(a.agent_name || a.nombre_agente).localeCompare(
      safeString(b.agent_name || b.nombre_agente)
    ) ||
    safeString(a.lead_name || a.nombre_lead || a.name).localeCompare(
      safeString(b.lead_name || b.nombre_lead || b.name)
    ) ||
    safeString(a.lead_id || a.id).localeCompare(
      safeString(b.lead_id || b.id)
    )
  );
}

function normalizeLeadId(row) {
  return firstNonEmpty(
    row.lead_id,
    row.id,
    row.personId,
    row.person_id
  );
}

function normalizeLeadName(row) {
  return firstNonEmpty(
    row.lead_name,
    row.nombre_lead,
    row.name
  );
}

function normalizeAgentName(row) {
  return firstNonEmpty(
