}

function normalizeWarningReason(row) {
  return firstNonEmpty(
    row.warning_reason,
    row.razon_nota,
    row.action_reason,
    row.reason
  );
}

function normalizeDestinationPond(row) {
  const pondId = firstNonEmpty(
    row.destination_pond_id,
    row.pond_nuevo_id,
    row.new_pond_id,
    272
  );

  const pondName = firstNonEmpty(
    row.destination_pond_name,
    row.pond_nuevo_nombre,
    row.new_pond_name,
    'Buyer Reassignment Pond'
  );

  return `${pondId} - ${pondName}`;
}

function normalizeWarningNoteSubject(row) {
  return firstNonEmpty(
    row.warning_note_subject,
    row.asunto_nota_warning,
    row.note_subject,
    row.payload?.subject,
    row.planned_body?.subject,
