}

function linkHtml(url, label = 'Open Lead') {
  const cleanUrl = safeTrim(url);
  if (!cleanUrl) return '';
  return `<a href="${escapeAttr(cleanUrl)}" target="_blank" rel="noopener noreferrer">${escapeHtml(label)}</a>`;
}

function statusBadge(status) {
  const clean = safeTrim(status);

  if (!clean) {
    return '<span style="display:inline-block;padding:3px 8px;border-radius:999px;background:#f1f5f9;color:#475569;font-size:12px;">N/A</span>';
  }

  let background = '#f1f5f9';
  let color = '#475569';

  if (clean === 'dry_run_ready') {
    background = '#e0f2fe';
    color = '#0369a1';
  } else if (clean === 'ready_to_execute') {
    background = '#dcfce7';
    color = '#166534';
  } else if (clean === 'prepared_report_only') {
    background = '#fef9c3';
    color = '#854d0e';
  } else if (clean.includes('blocked') || clean.includes('error')) {
    background = '#fee2e2';
    color = '#991b1b';
  }

  return `<span style="display:inline-block;padding:3px 8px;border-radius:999px;background:${background};color:${color};font-size:12px;">${escapeHtml(clean)}</span>`;
}

