function buildTableHtml({ columns, rows, emptyMessage }) {
  const headerHtml = columns
    .map(col => `
      <th style="text-align:left;padding:10px;border:1px solid #e5e7eb;background:#f8fafc;color:#334155;font-size:13px;">
        ${escapeHtml(col.label)}
      </th>
    `)
    .join('');

  const bodyHtml = rows.length
    ? rows.map(row => {
        const cells = columns.map(col => {
          const rawValue = col.value(row);
          const value = col.html === true ? rawValue : escapeHtml(cleanCell(rawValue));

          return `
            <td style="vertical-align:top;padding:10px;border:1px solid #e5e7eb;color:#111827;font-size:13px;line-height:1.35;">
              ${value}
            </td>
          `;
        }).join('');

        return `<tr>${cells}</tr>`;
      }).join('')
    : emptyStateHtml(emptyMessage);

  return `
    <table cellpadding="0" cellspacing="0" style="width:100%;border-collapse:collapse;margin-top:8px;margin-bottom:24px;">
      <thead>
        <tr>${headerHtml}</tr>
      </thead>
      <tbody>
        ${bodyHtml}
      </tbody>
    </table>
  `;
}

function buildSummaryCard(label, value) {
