/****************************************************************************************
 * NODE: Filter Leads by LastActivity > 30 Days
 * MODE: Run Once for All Items
 *
 * OBJETIVO:
 * - Leer todos los leads recibidos.
 * - Tomar como referencia principal LastActivity:
 *   lastActivity / last_activity_iso / last_activity
 * - Calcular días desde la última actividad.
 * - Si existen leads con LastActivity > 30 días:
 *   devuelve SOLO esos leads marcados.
 * - Si NO existen leads con LastActivity > 30 días:
 *   devuelve TODOS los registros exactamente como ingresaron.
 ****************************************************************************************/

const items = $input.all();

const THRESHOLD_DAYS = 30;
const MS_PER_DAY = 1000 * 60 * 60 * 24;

// Si quieres congelar fecha para pruebas, coloca ISO aquí.
// Ejemplo: const NOW_OVERRIDE = '2026-06-08T00:00:00Z';
const NOW_OVERRIDE = null;

const now = NOW_OVERRIDE ? new Date(NOW_OVERRIDE) : new Date();

function normalizeInput(items) {
  if (items.length > 1) {
    return items.map(item => item.json);
  }

  const first = items[0]?.json;

  if (Array.isArray(first)) return first;
  if (Array.isArray(first?.data)) return first.data;
  if (Array.isArray(first?.leads)) return first.leads;
  if (Array.isArray(first?.results)) return first.results;

  return first ? [first] : [];
}

function getLastActivityRaw(lead) {
  return (
    lead.lastActivity ??
    lead.last_activity_iso ??
    lead.last_activity ??
    lead.lastCommunication ??
    lead.last_communication ??
    null
  );
}

function parseDate(value) {
  if (!value) return null;

  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function calculateDaysSince(date) {
  if (!date) return null;

  const diff = now.getTime() - date.getTime();

  if (diff < 0) return 0;

  return Math.floor(diff / MS_PER_DAY);
}

const leads = normalizeInput(items);

const staleLeads = [];

for (const lead of leads) {
  const lastActivityRaw = getLastActivityRaw(lead);
  const lastActivityDate = parseDate(lastActivityRaw);

  let daysSinceLastActivity = calculateDaysSince(lastActivityDate);

  if (
    daysSinceLastActivity === null &&
    lead.days_since_last_activity !== undefined &&
    lead.days_since_last_activity !== null
  ) {
    const parsedDays = Number(lead.days_since_last_activity);
    daysSinceLastActivity = Number.isFinite(parsedDays) ? parsedDays : null;
  }

  const hasValidLastActivity = daysSinceLastActivity !== null;

  const isLastCommunicationOlderThan30d =
    hasValidLastActivity && daysSinceLastActivity > THRESHOLD_DAYS;

  if (isLastCommunicationOlderThan30d) {
    staleLeads.push({
      ...lead,

      last_activity_filter: {
        threshold_days: THRESHOLD_DAYS,
        reference_now: now.toISOString(),
        last_activity_raw: lastActivityRaw,
        last_activity_iso: lastActivityDate ? lastActivityDate.toISOString() : null,
        days_since_last_activity: daysSinceLastActivity,
        has_valid_last_activity: hasValidLastActivity,
        last_communication_gt_30d: true,
        filter_result: 'PASS_GT_30_DAYS',
      },

      // Campos planos útiles para IF / Merge / reporte
      last_communication_gt_30d: true,
      last_activity_filter_result: 'PASS_GT_30_DAYS',
    });
  }
}

/**
 * Si encontró leads con LastActivity > 30 días:
 * devuelve SOLO esos leads marcados.
 */
if (staleLeads.length > 0) {
  return staleLeads.map(lead => ({ json: lead }));
}

/**
 * Si NO encontró ningún lead con LastActivity > 30 días:
 * devuelve los items originales exactamente como entraron.
 */
return items;

/****************************************************************************************
 * NODE: Mark Last Communication Status
 * MODE: Run Once for All Items
 *
 * OBJETIVO:
 * - Revisar latest_call_date y latest_text_date.
 * - Determinar cuál es la última comunicación real.
 * - Calcular días desde esa última comunicación.
 * - Marcar perfiles con comunicación mayor a 30 días.
 * - Marcar también perfiles sin llamadas ni mensajes.
 * - NO filtra items: devuelve todos los perfiles enriquecidos.
 *
 * LÓGICA:
 * - Si llamada > 30d y texto > 30d  => FLAGGED
 * - Si llamada > 30d y texto <= 30d => NO FLAGGED
 * - Si llamada <= 30d y texto > 30d => NO FLAGGED
 * - Si llamada <= 30d y texto <=30d => NO FLAGGED
 * - Si no hay llamada ni texto       => FLAGGED
 ****************************************************************************************/

const items = $input.all();

const COMMUNICATION_THRESHOLD_DAYS = 30;
const MS_PER_DAY = 1000 * 60 * 60 * 24;

// Para pruebas puedes fijar una fecha:
// const NOW_OVERRIDE = '2026-06-08T00:00:00Z';
const NOW_OVERRIDE = null;

const now = NOW_OVERRIDE ? new Date(NOW_OVERRIDE) : new Date();

function parseDate(value) {
  if (!value) return null;

  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
}

function daysSinceDate(date) {
  if (!date) return null;

  const diffMs = now.getTime() - date.getTime();

  if (diffMs < 0) return 0;

  return Math.floor(diffMs / MS_PER_DAY);
}

function getLatestCommunication(profile) {
  const candidates = [];

  const callDate = parseDate(
    profile.latest_call_date ||
    profile.latest_call_started_at ||
    null
  );

  if (callDate) {
    candidates.push({
      source: 'call',
      date: callDate,
      raw: profile.latest_call_date || profile.latest_call_started_at,
      id: profile.latest_call_id ?? null,
      user_id: profile.latest_call_user_id ?? null,
      user_name: profile.latest_call_user_name ?? null,
      is_incoming: profile.latest_call_is_incoming ?? null,
    });
  }

  const textDate = parseDate(
    profile.latest_text_date ||
    profile.latest_text_sent_at ||
    profile.latest_text_updated_at ||
    null
  );

  if (textDate) {
    candidates.push({
      source: 'text',
      date: textDate,
      raw:
        profile.latest_text_date ||
        profile.latest_text_sent_at ||
        profile.latest_text_updated_at,
      id: profile.latest_text_id ?? null,
      user_id: profile.latest_text_user_id ?? null,
      user_name: profile.latest_text_user_name ?? null,
      is_incoming: profile.latest_text_is_incoming ?? null,
    });
  }

  if (candidates.length === 0) {
    return null;
  }

  candidates.sort((a, b) => b.date.getTime() - a.date.getTime());

  return candidates[0];
}

const output = items.map(item => {
  const profile = item.json;

  const latestCommunication = getLatestCommunication(profile);

  const hasLatestCommunication = Boolean(latestCommunication);

  const daysSinceLatestCommunication = latestCommunication
    ? daysSinceDate(latestCommunication.date)
    : null;

  const noCommunicationFound = !hasLatestCommunication;

  const lastCommunicationGt30d =
    noCommunicationFound ||
    daysSinceLatestCommunication > COMMUNICATION_THRESHOLD_DAYS;

  let communicationStatus = '';

  if (noCommunicationFound) {
    communicationStatus = 'NO_COMMUNICATION_FOUND_FLAGGED';
  } else if (lastCommunicationGt30d) {
    communicationStatus = 'STALE_GT_30_DAYS';
  } else {
    communicationStatus = 'RECENT_WITHIN_30_DAYS';
  }

  return {
    json: {
      ...profile,

      communication_review: {
        threshold_days: COMMUNICATION_THRESHOLD_DAYS,
        reference_now: now.toISOString(),

        latest_communication_found: hasLatestCommunication,

        latest_communication_date: latestCommunication
          ? latestCommunication.date.toISOString()
          : null,

        latest_communication_source: latestCommunication
          ? latestCommunication.source
          : null,

        latest_communication_raw: latestCommunication
          ? latestCommunication.raw
          : null,

        latest_communication_id: latestCommunication
          ? latestCommunication.id
          : null,

        latest_communication_user_id: latestCommunication
          ? latestCommunication.user_id
          : null,

        latest_communication_user_name: latestCommunication
          ? latestCommunication.user_name
          : null,

        latest_communication_is_incoming: latestCommunication
          ? latestCommunication.is_incoming
          : null,

        days_since_latest_communication: daysSinceLatestCommunication,

        no_communication_found: noCommunicationFound,

        last_communication_gt_30d: lastCommunicationGt30d,

        communication_status: communicationStatus,

        action_candidate_by_communication: lastCommunicationGt30d,
      },

      // Campos planos para usar fácil en IF, Switch, reportes o Sheets
      latest_communication_date: latestCommunication
        ? latestCommunication.date.toISOString()
        : null,

      latest_communication_source: latestCommunication
        ? latestCommunication.source
        : null,

      days_since_latest_communication: daysSinceLatestCommunication,

      no_communication_found: noCommunicationFound,

      last_communication_gt_30d: lastCommunicationGt30d,

      communication_status: communicationStatus,

      action_candidate_by_communication: lastCommunicationGt30d,
    },
  };
});

return output;

