parameters.jsCode:
/****************************************************************************************
 * NODE: Build Notes Profile
 * MODE: Run Once for All Items
 *
 * OBJETIVO:
 * - Leer respuesta de FUB /notes.
 * - Extraer notas del lead.
 * - Detectar warning notes previas de automatización.
 * - Reconocer los formatos históricos de warning.
 * - Calcular antigüedad de la warning note.
 * - Entregar un notes_profile para usarlo después en Build Full Lead Profile.
 ****************************************************************************************/

const items = $input.all();

const WARNING_ESCALATION_DAYS = 7;
const MS_PER_DAY = 1000 * 60 * 60 * 24;

// Para pruebas puedes fijar fecha.
// const NOW_OVERRIDE = '2026-06-10T00:00:00Z';
const NOW_OVERRIDE = null;

const now = NOW_OVERRIDE ? new Date(NOW_OVERRIDE) : new Date();

const OLD_N8N_WARNING_BODY_SIGNATURE =
  'n8n WARNING NOTE\nNo reassignment was applied because the lead has an active non-overdue task or is not eligible for reassignment under the current automation rules';

const VIKTOR_WARNING_BODY_SIGNATURE =
  'VIKTOR AUDIT: This lead has not been contacted in 30+ days and is actively browsing. Please follow up today or this lead will be reassigned on the next audit';

const CURRENT_N8N_WARNING_BODY_SIGNATURE =
  'n8n warning : This lead has not been contacted in 30+ days. Please follow up today or this lead will be reassigned on the next audit';

function normalizeText(value) {
  return String(value || '')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
}

function parseDate(value) {
  if (!value) return null;

  const d = new Date(value);
  return Number.isNaN(d.getTime()) ? null : d;
}

function daysSince(value) {
  const d = parseDate(value);
  if (!d) return null;

  const diffMs = now.getTime() - d.getTime();

  if (diffMs < 0) return 0;

  return Math.floor(diffMs / MS_PER_DAY);
}

function firstValidNumber(values) {
  for (const value of values) {
    const num = Number(value);
    if (Number.isFinite(num) && num > 0) {
      return num;
    }
  }

  return null;
}

function extractPersonIdFromUrl(url) {
  if (!url || typeof url !== 'string') return null;

  const match = url.match(/[?&]personId=(\d+)/);
  if (!match) return null;

  const num = Number(match[1]);
  return Number.isFinite(num) && num > 0 ? num : null;
}

function getResponseBody(json) {
  if (json.body && typeof json.body === 'object') {
    return json.body;
  }

  return json || {};
}

function getNotes(raw, response) {
  if (Array.isArray(response.notes)) return response.notes;
  if (Array.isArray(response.note)) return response.note;
  if (Array.isArray(response.data)) return response.data;
  if (Array.isArray(response.results)) return response.results;

  if (Array.isArray(raw.notes)) return raw.notes;
  if (Array.isArray(raw.data)) return raw.data;
  if (Array.isArray(raw.results)) return raw.results;

  return [];
}


function getSourceLeadFromLoop(index) {
  /**
   * Safety fallback:
   * The FUB /notes response can be empty, so the response may not contain personId.
   * This pulls the lead_id from the item that entered Loop Over Items2.
   */
  try {
    const loopItems = $('Loop Over Items2').all();
    return loopItems[index]?.json || loopItems[0]?.json || {};
  } catch (error) {
    try {
      const loopItems = $items('Loop Over Items2');
      return loopItems[index]?.json || loopItems[0]?.json || {};
    } catch (innerError) {
      return {};
    }
  }
}

function isAutomationWarningNote(note) {
  const subject = normalizeText(note.subject || '');
  const body = normalizeText(note.body || note.note || note.content || '');

  const oldN8nBody = normalizeText(OLD_N8N_WARNING_BODY_SIGNATURE);
  const viktorBody = normalizeText(VIKTOR_WARNING_BODY_SIGNATURE);
  const currentN8nBody = normalizeText(CURRENT_N8N_WARNING_BODY_SIGNATURE);

  const oldN8nMatch =
    subject.includes('n8n warning note') ||
    body.includes(oldN8nBody) ||
    (
      body.includes('n8n warning note') &&
      body.includes('no reassignment was applied')
    );

  const viktorMatch =
    body.includes(viktorBody) ||
    (
      body.includes('viktor audit') &&
      body.includes('this lead has not been contacted in 30+ days') &&
      body.includes('reassigned on the next audit')
    );

  const currentN8nMatch =
    subject === 'n8n warning' ||
    subject.includes('n8n warning') ||
    body.includes(currentN8nBody) ||
    (
      body.includes('n8n warning') &&
      body.includes('this lead has not been contacted in 30+ days') &&
      body.includes('reassigned on the next audit')
    );

  return Boolean(oldN8nMatch || viktorMatch || currentN8nMatch);
}

return items.map((item, index) => {
  const raw = item.json || {};
  const response = getResponseBody(raw);
  const sourceLead = getSourceLeadFromLoop(index);

  const statusCode =
    raw.statusCode ||
    raw.status ||
    response.statusCode ||
    response.status ||
    null;

  const notesApiError = Boolean(
    (statusCode && Number(statusCode) >= 400) ||
    raw.error ||
    response.error
  );

  const notes = getNotes(raw, response);

  const leadId = firstValidNumber([
    raw.lead_id,
    raw.id,
    raw.personId,
    raw.person_id,
    response.lead_id,
    response.id,
    response.personId,
    response.person_id,
    sourceLead.lead_id,
    sourceLead.id,
    sourceLead.personId,
    sourceLead.person_id,
    notes[0]?.personId,
    extractPersonIdFromUrl(response._metadata?.nextLink),
    extractPersonIdFromUrl(raw._metadata?.nextLink),
    extractPersonIdFromUrl(response._metadata?.selfLink),
    extractPersonIdFromUrl(raw._metadata?.selfLink),
  ]);

  const warningNotes = notes
    .filter(isAutomationWarningNote)
    .map(note => {
      const createdDate =
        note.created ||
        note.createdAt ||
        note.updated ||
        note.updatedAt ||
        null;

      return {
        id: note.id ?? null,
        personId: note.personId ?? leadId,
        created: createdDate,
        updated: note.updated ?? note.updatedAt ?? null,
        subject: note.subject ?? '',
        body: note.body ?? '',
        isHtml: note.isHtml ?? null,
        systemId: note.systemId ?? null,
        systemName: note.systemName ?? null,
        createdById: note.createdById ?? null,
        createdBy: note.createdBy ?? null,
        warning_age_days: daysSince(createdDate),
      };
    })
    .sort((a, b) => {
      const da = new Date(a.created || 0).getTime();
      const db = new Date(b.created || 0).getTime();
      return db - da;
    });

  const latestWarningNote = warningNotes[0] || null;

  const oldestWarningNote =
    warningNotes
      .filter(note => note.warning_age_days !== null)
      .sort((a, b) => b.warning_age_days - a.warning_age_days)[0] || null;

  const hasWarningOlderOrEqual7Days =
    warningNotes.some(note =>
      note.warning_age_days !== null &&
      note.warning_age_days >= WARNING_ESCALATION_DAYS
    );

  return {
    json: {
      lead_id: leadId,

      notes_profile_built: true,
      notes_api_error: notesApiError,
      notes_http_status_code: statusCode,

      notes_total_reported_by_fub:
        response._metadata?.total ??
        raw._metadata?.total ??
        notes.length,

      notes_total_returned: notes.length,

      warning_note_already_exists: warningNotes.length > 0,
      existing_warning_notes_count: warningNotes.length,

      has_warning_note_older_or_equal_7_days: hasWarningOlderOrEqual7Days,
      warning_note_escalation_threshold_days: WARNING_ESCALATION_DAYS,

      latest_warning_note_id: latestWarningNote?.id ?? null,
      latest_warning_note_created: latestWarningNote?.created ?? null,
      latest_warning_note_updated: latestWarningNote?.updated ?? null,
      latest_warning_note_age_days: latestWarningNote?.warning_age_days ?? null,
      latest_warning_note_subject: latestWarningNote?.subject ?? null,
      latest_warning_note_body: latestWarningNote?.body ?? null,
      latest_warning_note_system_id: latestWarningNote?.systemId ?? null,
      latest_warning_note_system_name: latestWarningNote?.systemName ?? null,

      oldest_warning_note_id: oldestWarningNote?.id ?? null,
      oldest_warning_note_created: oldestWarningNote?.created ?? null,
      oldest_warning_note_age_days: oldestWarningNote?.warning_age_days ?? null,

      warning_notes: warningNotes.map(note => ({
        id: note.id,
        personId: note.personId,
        created: note.created,
        updated: note.updated,
        subject: note.subject,
        body: note.body,
        systemId: note.systemId,
        systemName: note.systemName,
        warning_age_days: note.warning_age_days,
      })),

      notes_profile_status:
        notesApiError
          ? 'NOTES_API_ERROR'
          : warningNotes.length > 0
            ? 'WARNING_NOTES_FOUND'
            : 'NO_WARNING_NOTES_FOUND',

      build_notes_profile_index: index,
    },
  };
});

/****************************************************************************************
 * NODE: Note Rate Limit Wait
 * MODE: Run Once for Each Item via Loop Over Items1
 *
 * Purpose:
 * - Throttle note_create mutations before calling FUB /notes.
 * - FUB returned x-ratelimit-context=notes, x-ratelimit-limit=10,
 *   x-ratelimit-window=10, retry-after=7 in the failed run.
 * - 1.5s per note keeps us below 10 requests per 10 seconds.
 ****************************************************************************************/

const items = $input.all();
const NOTE_RATE_LIMIT_DELAY_MS = 1500;

await new Promise(resolve => setTimeout(resolve, NOTE_RATE_LIMIT_DELAY_MS));

return items;

/****************************************************************************************
 * NODE: Final Report Delay
 * MODE: Run Once for All Items
 *
 * Purpose:
 * - Prevent report from being sent from per-item loop branches.
 * - In EXECUTE mode, give FUB mutation branches enough time to finish before
 *   Builded planned changes reads Reassign Report / Note Report outputs.
 * - In DRY_RUN, return almost immediately.
 ****************************************************************************************/

const items = $input.all();

const preparedItems = items.map(item => item.json || {});
const executionMode = String(preparedItems[0]?.execution_mode || '').trim().toUpperCase();

const executableItems = preparedItems.filter(j =>
  j.execute_fub_changes === true &&
  j.mutation_prepared === true &&
  j.mutation_allowed === true &&
  j.prepare_execution_status === 'ready_to_execute'
);

const noteCount = executableItems.filter(j => j.mutation_type === 'note_create').length;
const reassignCount = executableItems.filter(j => j.mutation_type === 'reassign_pond').length;

let delayMs = 500;

if (executionMode === 'EXECUTE' && executableItems.length > 0) {
  /**
   * Notes are throttled at 1.5s each. Reassigns are usually faster, but we
   * reserve extra time so the final report can pick up execution results.
   * Cap at 55s to avoid long Code-node blocking.
   */
  delayMs = Math.min(
    Math.max(15000, (noteCount * 1700) + (reassignCount * 800) + 10000),
    55000
  );
}

await new Promise(resolve => setTimeout(resolve, delayMs));

return items;
